import React, { useMemo, useState, useEffect } from 'react';
import { 
  FileSpreadsheet, 
  Table, 
  TrendingDown, 
  FileText, 
  ArrowUpCircle, 
  Zap, 
  PiggyBank, 
  Wallet,
  Building2,
  ArrowRight
} from 'lucide-react';
import { Transaction, DailySummary, TransactionType, CategoryConfig } from '../types';
import DateDropdown, { DatePreset } from './DateDropdown';

interface ReportViewProps {
  transactions: Transaction[];
  summary: DailySummary;
  customCategories: CategoryConfig[];
  budgets: Record<string, number>;
}

const ReportView: React.FC<ReportViewProps> = ({ transactions, summary }) => {
  const todayStr = new Date().toISOString().split('T')[0];
  const [datePreset, setDatePreset] = useState<DatePreset>('thisMonth');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>(todayStr);

  useEffect(() => {
    const now = new Date();
    let start = '';
    let end = todayStr;

    switch (datePreset) {
      case 'today':
        start = todayStr;
        break;
      case 'yesterday':
        const yesterday = new Date(now);
        yesterday.setDate(now.getDate() - 1);
        start = yesterday.toISOString().split('T')[0];
        end = start;
        break;
      case 'last7':
        const last7 = new Date(now);
        last7.setDate(now.getDate() - 7);
        start = last7.toISOString().split('T')[0];
        break;
      case 'thisMonth':
        start = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
        break;
      case 'lastMonth':
        const firstOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
        const lastOfLastMonth = new Date(now.getFullYear(), now.getMonth(), 0);
        start = firstOfLastMonth.toISOString().split('T')[0];
        end = lastOfLastMonth.toISOString().split('T')[0];
        break;
      case 'all':
        start = '';
        break;
    }

    setStartDate(start);
    setEndDate(end);
  }, [datePreset, todayStr]);

  const formatCurrency = (val: number) => new Intl.NumberFormat(undefined, { 
    minimumFractionDigits: 2, 
    maximumFractionDigits: 2 
  }).format(val);

  // Grouped data for the simplified table
  const dailySummaryData = useMemo(() => {
    const filtered = transactions.filter(t => {
      if (startDate && t.date < startDate) return false;
      if (endDate && t.date > endDate) return false;
      return true;
    });

    const dates = Array.from(new Set(filtered.map(t => t.date))).sort().reverse();

    return dates.map(date => {
      const dayTxs = filtered.filter(t => t.date === date);
      const opening = dayTxs.filter(t => t.category === 'Opening Balance').reduce((s, t) => s + t.amount, 0);
      const income = dayTxs.filter(t => t.type === TransactionType.INCOME && t.category !== 'Opening Balance').reduce((s, t) => s + t.amount, 0);
      const expenses = dayTxs.filter(t => t.type === TransactionType.EXPENSE).reduce((s, t) => s + t.amount, 0);
      const savings = dayTxs.filter(t => t.type === TransactionType.SAVINGS).reduce((s, t) => s + t.amount, 0);
      const cashInHand = (opening + income) - (expenses + savings);

      return { date, opening, income, expenses, savings, cashInHand };
    });
  }, [transactions, startDate, endDate]);

  const bankBreakdown = useMemo(() => {
    const breakdown: Record<string, number> = {};
    transactions
      .filter(t => t.type === TransactionType.SAVINGS)
      .forEach(t => {
        const acc = t.account || 'General Savings';
        breakdown[acc] = (breakdown[acc] || 0) + t.amount;
      });
    return Object.entries(breakdown).sort((a, b) => b[1] - a[1]);
  }, [transactions]);

  const generateSimpleExcel = () => {
    let csv = "Date,Opening Balance,Daily Income,Daily Expenses,Savings,Cash in Hand\n";
    dailySummaryData.forEach(row => {
      csv += `${row.date},${row.opening},${row.income},${row.expenses},${row.savings},${row.cashInHand}\n`;
    });

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `SpendWise_Simple_Report_${datePreset}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-8 pb-12 animate-in fade-in slide-in-from-bottom-2 duration-500">
      {/* 1. Header & Export */}
      <div className="bg-white p-6 md:p-8 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="bg-slate-900 p-3 rounded-2xl">
            <FileText className="w-6 h-6 text-white" />
          </div>
          <div>
            <h2 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">Simple Daily Statement</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Clear Cash Flow Tracking</p>
          </div>
        </div>
        <button 
          onClick={generateSimpleExcel} 
          className="flex items-center gap-2 bg-emerald-600 text-white px-6 py-4 rounded-2xl font-black text-sm hover:bg-emerald-700 transition-all active:scale-95 shadow-lg shadow-emerald-100 justify-center"
        >
          <FileSpreadsheet className="w-5 h-5" />
          Download Excel (.csv)
        </button>
      </div>

      {/* 2. Key Metrics Summary */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 text-blue-600 mb-2">
            <Wallet className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Opening Bal.</span>
          </div>
          <p className="text-2xl font-black text-slate-900 tracking-tight">RS{formatCurrency(summary.openingBalance)}</p>
        </div>
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 text-emerald-600 mb-2">
            <ArrowUpCircle className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Total Income</span>
          </div>
          <p className="text-2xl font-black text-slate-900 tracking-tight">RS{formatCurrency(summary.totalIncome)}</p>
        </div>
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 text-rose-600 mb-2">
            <Zap className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Total Expenses</span>
          </div>
          <p className="text-2xl font-black text-slate-900 tracking-tight">RS{formatCurrency(summary.totalExpenses)}</p>
        </div>
        <div className="bg-indigo-600 p-6 rounded-[2rem] border border-indigo-500 shadow-xl shadow-indigo-100">
          <div className="flex items-center gap-2 text-indigo-100 mb-2">
            <TrendingDown className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Cash in Hand</span>
          </div>
          <p className="text-2xl font-black text-white tracking-tight">RS{formatCurrency(summary.currentBalance)}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* 3. Daily Table */}
        <div className="lg:col-span-8 bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Table className="w-5 h-5 text-slate-400" />
              <h3 className="font-black text-slate-800 text-sm uppercase tracking-widest">Day-by-Day View</h3>
            </div>
            <DateDropdown value={datePreset} onChange={setDatePreset} />
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 text-[10px] uppercase font-black text-slate-400 tracking-widest border-b border-slate-100">
                  <th className="px-6 py-4">Date</th>
                  <th className="px-6 py-4 text-right">Income</th>
                  <th className="px-6 py-4 text-right">Expenses</th>
                  <th className="px-6 py-4 text-right">Savings</th>
                  <th className="px-6 py-4 text-right">Net Cash</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {dailySummaryData.map((day, i) => (
                  <tr key={i} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4 text-xs font-black text-slate-500">{day.date}</td>
                    <td className="px-6 py-4 text-right text-sm font-black text-emerald-600">+{day.income.toFixed(2)}</td>
                    <td className="px-6 py-4 text-right text-sm font-black text-rose-500">-{day.expenses.toFixed(2)}</td>
                    <td className="px-6 py-4 text-right text-sm font-black text-indigo-500">-{day.savings.toFixed(2)}</td>
                    <td className="px-6 py-4 text-right">
                      <span className="bg-slate-100 px-3 py-1 rounded-full text-xs font-black text-slate-900">
                        {day.cashInHand.toFixed(2)}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* 4. Bank-Wise Savings Breakdown */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm space-y-6">
            <div className="flex items-center gap-2">
              <Building2 className="w-5 h-5 text-indigo-600" />
