      {['reports', 'budget', 'settings'].includes(activeTab) && (
        <div className="md:hidden fixed top-14 left-0 right-0 bg-white/90 backdrop-blur-md border-b border-slate-200 z-[90] overflow-x-auto scrollbar-hide py-3 px-4">
