import { GoogleGenAI } from "@google/genai";
import { Transaction } from "../types";

// Simple In-Memory Cache And Throttle
let lastCallTime = 0;
const THROTTLE_MS = 30000; // Reduced throttle for Flash model

export const getFinancialInsights = async (transactions: Transaction[]): Promise<string> => {
  if (transactions.length === 0) return "Add Some Transactions To Get Ai-Powered Financial Insights!";

  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    return "Ai Insights Require An Api Key. Please Configure The Api_Key Environment Variable.";
  }

  const now = Date.now();
  if (now - lastCallTime < THROTTLE_MS) {
    return "Analyzing your trends... Please wait a few seconds for the next update.";
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const sortedTxs = [...transactions].sort((a, b) => b.date.localeCompare(a.date));
    const recentSummary = sortedTxs.slice(0, 40).map(t => 
      `${t.date}: ${t.type} - ${t.category}: Rs ${t.amount} (${t.note})`
    ).join('\n');

    // Switching to gemini-3-flash-preview to mitigate 429/Resource Exhausted errors
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a professional financial advisor. Analyze the following financial activity.

      TASK:
      1. Review the recent transactions provided below.
      2. Identify spending trends and patterns.
      3. Provide 4 concise, actionable insights focused on:
         - Category spending spikes (e.g., fuel, food).
         - Savings growth vs. expense ratio.
         - A "power move" to increase liquid cash next month.

      Transactions:
      ${recentSummary}`,
      config: {
        temperature: 0.7,
      }
    });

    lastCallTime = Date.now();
    return response.text || "I'm currently observing your spending. Add more data for a deeper analysis!";
  } catch (error: any) {
    console.error("Gemini Error:", error);

    const errorStr = JSON.stringify(error).toLowerCase();
    if (errorStr.includes('429') || errorStr.includes('resource_exhausted')) {
      return "The AI engine is temporarily busy due to high demand. Your data is safe and local charts are fully active. I'll provide new insights in a moment!";
    }

    return "Financial AI is synchronizing. Please check back in a few minutes.";
  }
};

