   </Row>
   <Row ss:Height="20"><Cell ss:StyleID="BoldLabel"><Data ss:Type="String">Total Inflow (Income)</Data></Cell><Cell ss:StyleID="Currency"><Data ss:Type="Number">${fullPeriodSummary.income}</Data></Cell></Row>
   <Row ss:Height="20"><Cell ss:StyleID="BoldLabel"><Data ss:Type="String">Total Operational Expenses</Data></Cell><Cell ss:StyleID="Currency"><Data ss:Type="Number">${fullPeriodSummary.expense}</Data></Cell></Row>
   <Row ss:Height="20"><Cell ss:StyleID="BoldLabel"><Data ss:Type="String">Total Savings / Investments</Data></Cell><Cell ss:StyleID="Currency"><Data ss:Type="Number">${fullPeriodSummary.savings}</Data></Cell></Row>
   <Row ss:Height="25"><Cell ss:StyleID="TotalStyle"><Data ss:Type="String">Net Period Surplus</Data></Cell><Cell ss:StyleID="TotalStyle" ss:StyleExt="Currency"><Data ss:Type="Number">${fullPeriodSummary.net}</Data></Cell></Row>
  </Table>
 </Worksheet>

 <Worksheet ss:Name="Daily Matrix Analysis">
  <Table ss:DefaultColumnWidth="110">
   <Row ss:Height="25">
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Date</Data></Cell>
    ${incomeCats.map((cat: string) => `<Cell ss:StyleID="IncomeHeader"><Data ss:Type="String">${escapeXML(cat)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="IncomeHeader"><Data ss:Type="String">Total Income</Data></Cell>
    ${expenseCats.map((cat: string) => `<Cell ss:StyleID="ExpenseHeader"><Data ss:Type="String">${escapeXML(cat)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="ExpenseHeader"><Data ss:Type="String">Total Expense</Data></Cell>
    ${savingsCats.map((cat: string) => `<Cell ss:StyleID="SavingsHeader"><Data ss:Type="String">${escapeXML(cat)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="SavingsHeader"><Data ss:Type="String">Total Savings</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Net Daily Flow</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Running Balance</Data></Cell>
   </Row>`;

    ledgerData.forEach((day: LedgerDay) => {
