  TrendingDown, 
  FileText, 
  Filter, 
  ArrowRightLeft, 
  PiggyBank, 
  Landmark,
  PieChart as PieChartIcon,
  Zap,
  ArrowUpCircle,
  ChevronDown
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
