          </div>
          <div>
            <h2 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight capitalize">Full Analytical Report</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Multi-Sheet Matrix Export</p>
          </div>
        </div>
        <button 
          onClick={generateExcelXML} 
          className="flex items-center gap-2 bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black text-sm hover:bg-emerald-700 transition-all active:scale-95 shadow-xl shadow-emerald-100 justify-center"
        >
          <FileSpreadsheet className="w-5 h-5" />
          Generate Excel Matrix (.xls)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 text-blue-600 mb-2">
            <Landmark className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Opening Bal.</span>
          </div>
          <p className="text-2xl font-black text-slate-900 tracking-tight">RS{formatCurrency(summary.openingBalance)}</p>
        </div>
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 text-emerald-600 mb-2">
            <ArrowUpCircle className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Income</span>
          </div>
          <p className="text-2xl font-black text-slate-900 tracking-tight">RS{formatCurrency(summary.totalIncome)}</p>
        </div>
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 text-rose-600 mb-2">
            <Zap className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Expenses</span>
          </div>
          <p className="text-2xl font-black text-slate-900 tracking-tight">RS{formatCurrency(summary.totalExpenses)}</p>
        </div>
        <div className="bg-indigo-600 p-6 rounded-[2rem] border border-indigo-500 shadow-xl shadow-indigo-100">
          <div className="flex items-center gap-2 text-indigo-100 mb-2">
            <TrendingDown className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Cash in Hand</span>
          </div>
          <p className="text-2xl font-black text-white tracking-tight">RS{formatCurrency(summary.currentBalance)}</p>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-2">
            <Table className="w-5 h-5 text-slate-400" />
            <h3 className="font-black text-slate-800 text-sm uppercase tracking-widest">Ledger Preview</h3>
          </div>
          <DateDropdown value={datePreset} onChange={setDatePreset} />
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 text-[10px] uppercase font-black text-slate-400 tracking-widest border-b border-slate-100">
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4 text-right">Day Income</th>
                <th className="px-6 py-4 text-right">Day Expenses</th>
                <th className="px-6 py-4 text-right">Day Savings</th>
                <th className="px-6 py-4 text-right">Cash in Hand</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {ledgerData.map((day: LedgerDay, i: number) => (
                <tr key={i} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4 text-xs font-black text-slate-500">{day.date}</td>
                  <td className="px-6 py-4 text-right text-sm font-black text-emerald-600">+{day.income.toFixed(2)}</td>
                  <td className="px-6 py-4 text-right text-sm font-black text-rose-500">-{day.expenses.toFixed(2)}</td>
                  <td className="px-6 py-4 text-right text-sm font-black text-indigo-500">-{day.savings.toFixed(2)}</td>
                  <td className="px-6 py-4 text-right">
                    <span className="bg-slate-100 px-3 py-1 rounded-full text-xs font-black text-slate-900">
                      {day.available.toFixed(2)}
                    </span>
                  </td>
                </tr>
              ))}
              {ledgerData.length === 0 && (
                <tr><td colSpan={5} className="py-20 text-center text-slate-300 font-bold capitalize">No data for this period.</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ReportView;

import React, { useMemo, useState, useEffect } from 'react';
import { 
  FileSpreadsheet, 
  Table, 
  CalendarDays, 
  TrendingDown, 
  FileText, 
  Filter, 
  ArrowRightLeft, 
  PiggyBank, 
  Landmark,
  PieChart as PieChartIcon,
  Zap,
  ArrowUpCircle,
  ChevronDown
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell
} from 'recharts';
import { Transaction, DailySummary, TransactionType, CategoryConfig } from './types';
import { getCategoryConfig } from './constants';
import DateDropdown, { DatePreset } from './components/DateDropdown';

// Define explicit interface for day summary to avoid 'any' and 'unknown' indexing issues
interface LedgerDay {
  date: string;
  income: number;
  expenses: number;
  savings: number;
  available: number;
  categories: Record<string, number>;
}

interface ReportViewProps {
  transactions: Transaction[];
  summary: DailySummary;
  customCategories: CategoryConfig[];
  budgets: Record<string, number>;
}

const ReportView: React.FC<ReportViewProps> = ({ transactions, summary, customCategories }) => {
  const todayStr = new Date().toISOString().split('T')[0];

  const [datePreset, setDatePreset] = useState<DatePreset>('thisMonth');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>(todayStr);
  const [typeFilter, setTypeFilter] = useState<'ALL' | TransactionType>('ALL');

  useEffect(() => {
    const now = new Date();
    let start = '';
    let end = todayStr;

    switch (datePreset) {
      case 'today':
        start = todayStr;
        end = todayStr;
        break;
      case 'yesterday':
        const yesterday = new Date(now);
        yesterday.setDate(now.getDate() - 1);
        start = yesterday.toISOString().split('T')[0];
        end = start;
        break;
      case 'last7':
        const last7 = new Date(now);
        last7.setDate(now.getDate() - 7);
        start = last7.toISOString().split('T')[0];
        end = todayStr;
        break;
      case 'thisMonth':
        start = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
        end = todayStr;
        break;
      case 'lastMonth':
        const firstOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
        const lastOfLastMonth = new Date(now.getFullYear(), now.getMonth(), 0);
        start = firstOfLastMonth.toISOString().split('T')[0];
        end = lastOfLastMonth.toISOString().split('T')[0];
        break;
      case 'all':
        start = '';
        end = todayStr;
        break;
      case 'custom':
        return;
    }

    setStartDate(start);
    setEndDate(end);
  }, [datePreset, todayStr]);

  const escapeXML = (str: any) => {
    if (str === null || str === undefined) return '';
    return str.toString()
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&apos;');
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat(undefined, { 
    minimumFractionDigits: 2, 
    maximumFractionDigits: 2 
  }).format(val);

  const periodTransactions = useMemo(() => {
    return transactions.filter(t => {
      let matchesDate = true;
      if (startDate) matchesDate = t.date >= startDate;
      if (matchesDate && endDate) matchesDate = matchesDate && t.date <= endDate;

      if (!matchesDate) return false;
      if (typeFilter !== 'ALL' && t.type !== typeFilter) return false;

      return true;
    }).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, startDate, endDate, typeFilter]);

  const fullPeriodSummary = useMemo(() => {
    let income = 0, expense = 0, savings = 0;
    periodTransactions.forEach(t => {
      if (t.type === TransactionType.INCOME) income += t.amount;
      else if (t.type === TransactionType.EXPENSE) expense += t.amount;
      else if (t.type === TransactionType.SAVINGS) savings += t.amount;
    });
    return { income, expense, savings, net: income - expense - savings };
  }, [periodTransactions]);

  const ledgerData = useMemo(() => {
    const allDates: string[] = Array.from(new Set(transactions.map(t => t.date))).sort() as string[];
    const ledgerMap: Record<string, LedgerDay> = {};
    let runningBalance = 0;

    allDates.forEach((date: string) => {
      const dayTxs = transactions.filter(t => t.date === date);
      const dayIncome = dayTxs.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
      const dayExpenses = dayTxs.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
      const daySavings = dayTxs.filter(t => t.type === TransactionType.SAVINGS).reduce((sum, t) => sum + t.amount, 0);

      const catBreakdown: Record<string, number> = {};
      dayTxs.forEach((t: Transaction) => {
        catBreakdown[t.category] = (catBreakdown[t.category] || 0) + t.amount;
      });

      runningBalance += dayIncome - dayExpenses - daySavings;

      ledgerMap[date] = { 
        date, 
        income: dayIncome, 
        expenses: dayExpenses,
        savings: daySavings,
        available: runningBalance,
        categories: catBreakdown
      };
    });

    return Object.keys(ledgerMap)
      .filter(date => {
        let matches = true;
        if (startDate) matches = date >= startDate;
        if (matches && endDate) matches = matches && date <= endDate;
        return matches;
      })
      .map(date => ledgerMap[date]);
  }, [transactions, startDate, endDate]);

  const categoryConcentrationData = useMemo(() => {
    const dataMap: Record<string, { amount: number, color: string }> = {};
    periodTransactions
      .forEach(t => {
        if (!dataMap[t.category]) {
          const config = getCategoryConfig(t.category, customCategories);
          dataMap[t.category] = { amount: 0, color: config.color };
        }
        dataMap[t.category].amount += t.amount;
      });
    return Object.entries(dataMap)
      .map(([name, data]: [string, { amount: number, color: string }]) => ({
        name,
        amount: data.amount,
        color: data.color
      }))
      .sort((a, b) => b.amount - a.amount);
  }, [periodTransactions, customCategories]);

  const generateExcelXML = () => {
    const periodLabel: string = escapeXML(`${startDate} to ${endDate}`);

    // Fix: Explicitly cast category lists as string[] to resolve unknown type inference errors
    const incomeCats = Array.from(new Set(periodTransactions.filter(t => t.type === TransactionType.INCOME).map(t => t.category))).sort() as string[];
    const expenseCats = Array.from(new Set(periodTransactions.filter(t => t.type === TransactionType.EXPENSE).map(t => t.category))).sort() as string[];
    const savingsCats = Array.from(new Set(periodTransactions.filter(t => t.type === TransactionType.SAVINGS).map(t => t.category))).sort() as string[];

    const columnTotals: Record<string, number> = {};
    [...incomeCats, ...expenseCats, ...savingsCats].forEach((cat: string) => {
      columnTotals[cat] = periodTransactions.filter(t => t.category === cat).reduce((s, t) => s + (Number(t.amount) || 0), 0);
    });

    let xml = `<?xml version="1.0" encoding="UTF-8"?><?mso-application progid="Excel.Sheet"?>
<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:o="urn:schemas-microsoft-com:office:office"
 xmlns:x="urn:schemas-microsoft-com:office:excel"
 xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:html="http://www.w3.org/TR/REC-html40">
 <Styles>
  <Style ss:ID="Default" ss:Name="Normal">
   <Alignment ss:Vertical="Bottom"/>
   <Borders/>
   <Font ss:FontName="Segoe UI" ss:Size="11" ss:Color="#1E293B"/>
  </Style>
  <Style ss:ID="TitleStyle">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Size="16" ss:Color="#0F172A"/>
  </Style>
  <Style ss:ID="IncomeHeader">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#FFFFFF"/>
   <Interior ss:Color="#10B981" ss:Pattern="Solid"/>
   <Alignment ss:Horizontal="Center" ss:Vertical="Center"/>
  </Style>
  <Style ss:ID="ExpenseHeader">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#FFFFFF"/>
   <Interior ss:Color="#F43F5E" ss:Pattern="Solid"/>
   <Alignment ss:Horizontal="Center" ss:Vertical="Center"/>
  </Style>
  <Style ss:ID="SavingsHeader">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#FFFFFF"/>
   <Interior ss:Color="#6366F1" ss:Pattern="Solid"/>
   <Alignment ss:Horizontal="Center" ss:Vertical="Center"/>
  </Style>
  <Style ss:ID="SummaryHeader">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#FFFFFF"/>
   <Interior ss:Color="#334155" ss:Pattern="Solid"/>
   <Alignment ss:Horizontal="Center" ss:Vertical="Center"/>
  </Style>
  <Style ss:ID="TotalStyle">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#1E293B"/>
   <Interior ss:Color="#F1F5F9" ss:Pattern="Solid"/>
   <Borders><Border ss:Position="Top" ss:LineStyle="Double" ss:Weight="3"/></Borders>
  </Style>
  <Style ss:ID="BoldLabel">
   <Font ss:FontName="Segoe UI" ss:Bold="1"/>
  </Style>
  <Style ss:ID="CenterText">
   <Alignment ss:Horizontal="Center"/>
  </Style>
  <Style ss:ID="Currency">
   <NumberFormat ss:Format="&quot;RS&quot;#,##0.00"/>
  </Style>
 </Styles>

 <Worksheet ss:Name="Executive Summary">
  <Table ss:DefaultColumnWidth="180">
   <Row ss:Height="40"><Cell ss:StyleID="TitleStyle"><Data ss:Type="String">Wealth Assessment Report: ${periodLabel}</Data></Cell></Row>
   <Row ss:Height="25">
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Metric Description</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Period Total Value</Data></Cell>
   </Row>
   <Row ss:Height="20"><Cell ss:StyleID="BoldLabel"><Data ss:Type="String">Total Inflow (Income)</Data></Cell><Cell ss:StyleID="Currency"><Data ss:Type="Number">${fullPeriodSummary.income}</Data></Cell></Row>
   <Row ss:Height="20"><Cell ss:StyleID="BoldLabel"><Data ss:Type="String">Total Operational Expenses</Data></Cell><Cell ss:StyleID="Currency"><Data ss:Type="Number">${fullPeriodSummary.expense}</Data></Cell></Row>
   <Row ss:Height="20"><Cell ss:StyleID="BoldLabel"><Data ss:Type="String">Total Savings / Investments</Data></Cell><Cell ss:StyleID="Currency"><Data ss:Type="Number">${fullPeriodSummary.savings}</Data></Cell></Row>
   <Row ss:Height="25"><Cell ss:StyleID="TotalStyle"><Data ss:Type="String">Net Period Surplus</Data></Cell><Cell ss:StyleID="TotalStyle" ss:StyleExt="Currency"><Data ss:Type="Number">${fullPeriodSummary.net}</Data></Cell></Row>
  </Table>
 </Worksheet>

 <Worksheet ss:Name="Daily Matrix Analysis">
  <Table ss:DefaultColumnWidth="110">
   <Row ss:Height="25">
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Date</Data></Cell>
    ${incomeCats.map((cat: string) => `<Cell ss:StyleID="IncomeHeader"><Data ss:Type="String">${escapeXML(cat)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="IncomeHeader"><Data ss:Type="String">Total Income</Data></Cell>
    ${expenseCats.map((cat: string) => `<Cell ss:StyleID="ExpenseHeader"><Data ss:Type="String">${escapeXML(cat)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="ExpenseHeader"><Data ss:Type="String">Total Expense</Data></Cell>
    ${savingsCats.map((cat: string) => `<Cell ss:StyleID="SavingsHeader"><Data ss:Type="String">${escapeXML(cat)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="SavingsHeader"><Data ss:Type="String">Total Savings</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Net Daily Flow</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Running Balance</Data></Cell>
   </Row>`;

    ledgerData.forEach((day: LedgerDay) => {
      xml += `
   <Row>
    <Cell ss:StyleID="CenterText"><Data ss:Type="String">${escapeXML(day.date)}</Data></Cell>
    ${incomeCats.map((cat: string) => `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.categories[cat] || 0}</Data></Cell>`).join('')}
    <Cell ss:StyleID="IncomeHeader" ss:StyleExt="Currency"><Data ss:Type="Number">${day.income}</Data></Cell>
    ${expenseCats.map((cat: string) => `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.categories[cat] || 0}</Data></Cell>`).join('')}
    <Cell ss:StyleID="ExpenseHeader" ss:StyleExt="Currency"><Data ss:Type="Number">${day.expenses}</Data></Cell>
    ${savingsCats.map((cat: string) => `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.categories[cat] || 0}</Data></Cell>`).join('')}
    <Cell ss:StyleID="SavingsHeader" ss:StyleExt="Currency"><Data ss:Type="Number">${day.savings}</Data></Cell>
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.income - day.expenses - day.savings}</Data></Cell>
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.available}</Data></Cell>
   </Row>`;
    });

    xml += `
  </Table>
 </Worksheet>

 <Worksheet ss:Name="Itemized Transaction Log">
  <Table ss:DefaultColumnWidth="140">
   <Row ss:Height="25">
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Date</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Type</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Category</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Amount</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Note / Details</Data></Cell>
   </Row>`;

    periodTransactions.slice().reverse().forEach(t => {
      xml += `
   <Row>
    <Cell ss:StyleID="CenterText"><Data ss:Type="String">${escapeXML(t.date)}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXML(t.type)}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXML(t.category)}</Data></Cell>
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${t.amount}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXML(t.note)}</Data></Cell>
   </Row>`;
    });

    xml += `
  </Table>
 </Worksheet>
</Workbook>`;

    const blob = new Blob([xml], { type: 'text/xml;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `SpendWise_Complete_Financial_Report_${startDate}_to_${endDate}.xls`;
