   <Row ss:Height="20"><Cell ss:StyleID="BoldLabel"><Data ss:Type="String">Total Operational Expenses</Data></Cell><Cell ss:StyleID="Currency"><Data ss:Type="Number">${fullPeriodSummary.expense}</Data></Cell></Row>
   <Row ss:Height="20"><Cell ss:StyleID="BoldLabel"><Data ss:Type="String">Total Savings / Investments</Data></Cell><Cell ss:StyleID="Currency"><Data ss:Type="Number">${fullPeriodSummary.savings}</Data></Cell></Row>
  </Table>
 </Worksheet>

 <Worksheet ss:Name="Daily Matrix Analysis">
  <Table ss:DefaultColumnWidth="130">
   <Row ss:Height="25">
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Date</Data></Cell>
    ${incomeCats.map((cat: string) => `<Cell ss:StyleID="IncomeHeader"><Data ss:Type="String">${getEmoji(cat as string)} ${escapeXML(cat)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="IncomeHeader"><Data ss:Type="String">📈 Total Income</Data></Cell>
    ${expenseCats.map((cat: string) => `<Cell ss:StyleID="ExpenseHeader"><Data ss:Type="String">${getEmoji(cat as string)} ${escapeXML(cat)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="ExpenseHeader"><Data ss:Type="String">📉 Total Expense</Data></Cell>
    ${savingsCats.map((cat: string) => `<Cell ss:StyleID="SavingsHeader"><Data ss:Type="String">${getEmoji(cat as string)} ${escapeXML(cat)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="SavingsHeader"><Data ss:Type="String">💰 Total Savings</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">🏦 Running Balance</Data></Cell>
   </Row>`;

    ledgerData.forEach((day: LedgerDay) => {
      xml += `
   <Row>
    <Cell ss:StyleID="Default"><Data ss:Type="String">${escapeXML(day.date)}</Data></Cell>
    ${incomeCats.map((cat: string) => `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.categories[cat as string] || 0}</Data></Cell>`).join('')}
    <Cell ss:StyleID="IncomeHeader"><Data ss:Type="Number">${day.income}</Data></Cell>
    ${expenseCats.map((cat: string) => `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.categories[cat as string] || 0}</Data></Cell>`).join('')}
    <Cell ss:StyleID="ExpenseHeader"><Data ss:Type="Number">${day.expenses}</Data></Cell>
    ${savingsCats.map((cat: string) => `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.categories[cat as string] || 0}</Data></Cell>`).join('')}
    <Cell ss:StyleID="SavingsHeader"><Data ss:Type="Number">${day.savings}</Data></Cell>
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.available}</Data></Cell>
   </Row>`;
    });

    xml += `
  </Table>
 </Worksheet>

 <Worksheet ss:Name="Visual Category Reference">
  <Table ss:DefaultColumnWidth="180">
   <Row ss:Height="25">
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Category Icon</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Name</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Financial Type</Data></Cell>
   </Row>`;

    const allDistinctCats = Array.from(new Set(periodTransactions.map(t => t.category))).sort();
    allDistinctCats.forEach(catName => {
      const config = getCategoryConfig(catName, customCategories);
      xml += `
   <Row>
    <Cell ss:StyleID="Default"><Alignment ss:Horizontal="Center"/><Data ss:Type="String">${getEmoji(catName)}</Data></Cell>
    <Cell ss:StyleID="BoldLabel"><Data ss:Type="String">${escapeXML(catName)}</Data></Cell>
    <Cell ss:StyleID="Default"><Data ss:Type="String">${config.type}</Data></Cell>
   </Row>`;
    });

    xml += `
  </Table>
 </Worksheet>

 <Worksheet ss:Name="Itemized Log">
  <Table ss:DefaultColumnWidth="140">
   <Row ss:Height="25">
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Date</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Category</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Amount</Data></Cell>
    <Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Notes</Data></Cell>
   </Row>`;

    periodTransactions.slice().reverse().forEach(t => {
      xml += `
   <Row>
    <Cell><Data ss:Type="String">${escapeXML(t.date)}</Data></Cell>
    <Cell><Data ss:Type="String">${getEmoji(t.category)} ${escapeXML(t.category)}</Data></Cell>
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${t.amount}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXML(t.note)}</Data></Cell>
   </Row>`;
    });

    xml += `
  </Table>
 </Worksheet>
</Workbook>`;

    const blob = new Blob([xml], { type: 'text/xml;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `SpendWise_Visual_Report_${startDate}_to_${endDate}.xls`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
