          <div className="h-[400px] w-full bg-slate-50/30 p-8 rounded-[3rem] border border-slate-100">
            {categoryConcentrationData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={categoryConcentrationData} layout="vertical" margin={{ left: 40, right: 40, top: 10, bottom: 10 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#e2e8f0" />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} width={120} tick={{ fontSize: 10, fontWeight: 900, fill: '#64748b' }} />
                  <Tooltip cursor={{ fill: 'rgba(226, 232, 240, 0.4)' }} contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.1)', padding: '16px' }} formatter={(value: number) => [`RS${formatCurrency(value)}`, 'Total']} />
                  <Bar dataKey="amount" radius={[0, 12, 12, 0]} barSize={32}>
                    {categoryConcentrationData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4"><CalendarDays className="w-16 h-16 opacity-10" /><p className="text-sm font-black uppercase tracking-[0.2em] opacity-30 capitalize">No Categorical Data Found In This View</p></div>
            )}
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2.5 rounded-2xl border border-slate-200 shadow-sm"><Table className="w-5 h-5 text-emerald-600" /></div>
            <div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight capitalize">Period Financial Log</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5 capitalize">Itemized Historical Settlements</p>
            </div>
          </div>
          <div className="bg-white px-4 py-2 rounded-2xl border border-slate-200 shadow-sm"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest capitalize">{periodTransactions.length} Verified Entries</span></div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[900px]">
            <thead>
              <tr className="bg-slate-50 text-[10px] uppercase tracking-widest text-slate-500 font-black border-b border-slate-200 capitalize"><th className="px-8 py-5">Value Date</th><th className="px-8 py-5">Category Context</th><th className="px-8 py-5">Note / Details</th><th className="px-8 py-5 text-right">Settled Amount</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100 font-mono text-xs">
              {periodTransactions.slice().reverse().map((row: Transaction) => (
                <tr key={row.id} className="hover:bg-slate-50/80 transition-colors group">
                  <td className="px-8 py-5 font-bold text-slate-400 group-hover:text-slate-800 transition-colors">{row.date}</td>
                  <td className="px-8 py-5 font-black text-slate-800 uppercase tracking-tight capitalize">{row.category}</td>
                  <td className="px-8 py-5 italic text-slate-500 capitalize">{row.note}</td>
                  <td className={`px-8 py-5 text-right font-black text-sm tracking-tight ${row.type === TransactionType.INCOME ? 'text-emerald-600' : row.type === TransactionType.SAVINGS ? 'text-teal-600' : 'text-slate-900'}`}>{row.type === TransactionType.EXPENSE ? '-' : row.type === TransactionType.SAVINGS ? '→' : '+'}RS{formatCurrency(row.amount)}</td>
                </tr>
              ))}
              {periodTransactions.length === 0 && (
                <tr><td colSpan={4} className="py-24 text-center"><div className="flex flex-col items-center gap-4 opacity-10"><TrendingDown className="w-16 h-16" /><p className="text-sm font-black uppercase tracking-[0.2em] capitalize">Zero Transactions Found For Criteria</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ReportView;

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, TransactionType, Category, DailySummary, CategoryConfig } from './types';
import { DEFAULT_CATEGORIES, getCategoryConfig, ICON_MAP } from './constants';
import TransactionForm from './components/TransactionForm';
import Stats from './components/Stats';
import Charts from './components/Charts';
import AIAssistant from './components/AIAssistant';
import ReportView from './components/ReportView';
import BudgetManager from './components/BudgetManager';
import BudgetProgress from './components/BudgetProgress';
import CategoryManager from './components/CategoryManager';
import CompoundSavings from './components/CompoundSavings';
import DateDropdown, { DatePreset } from './components/DateDropdown';
import { Trash2, Wallet, LayoutDashboard, FileText, Target, ArrowUpCircle, MoreHorizontal, Zap, Settings, Sparkles, PiggyBank, Edit3, PlusCircle } from 'lucide-react';

type TabType = 'overview' | 'income' | 'expenses' | 'savings' | 'reports' | 'budget' | 'settings';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('overview');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [ledgerDateFilter, setLedgerDateFilter] = useState<DatePreset>('all');
  const [preselectedCategory, setPreselectedCategory] = useState<string | null>(null);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('spendwise_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [budgets, setBudgets] = useState<Record<string, number>>(() => {
    const saved = localStorage.getItem('spendwise_budgets');
    return saved ? JSON.parse(saved) : {};
  });

  const [customCategories, setCustomCategories] = useState<CategoryConfig[]>(() => {
    const saved = localStorage.getItem('spendwise_custom_categories');
    return saved ? JSON.parse(saved) : [];
  });

  const [accounts, setAccounts] = useState<string[]>(() => {
    const saved = localStorage.getItem('spendwise_bank_accounts');
    return saved ? JSON.parse(saved) : ['Commercial Bank', 'Amana Bank'];
  });

  useEffect(() => {
    localStorage.setItem('spendwise_transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('spendwise_budgets', JSON.stringify(budgets));
  }, [budgets]);

  useEffect(() => {
    localStorage.setItem('spendwise_custom_categories', JSON.stringify(customCategories));
  }, [customCategories]);

  useEffect(() => {
    localStorage.setItem('spendwise_bank_accounts', JSON.stringify(accounts));
  }, [accounts]);

  const toTitleCase = (str: string) => str.toLowerCase().split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

  const addAccount = (name: string) => {
    const titleCased = toTitleCase(name);
    if (!accounts.includes(titleCased)) {
      setAccounts(prev => [...prev, titleCased]);
    }
  };

  const saveTransaction = (newTransaction: Transaction) => {
    setTransactions(prev => {
      if (editingTransaction) {
        setEditingTransaction(null);
        return prev.map(t => t.id === newTransaction.id ? newTransaction : t);
      }
      return [newTransaction, ...prev];
    });
    setPreselectedCategory(null);
  };

  const removeTransaction = (id: string) => {
    if (window.confirm("Remove This Entry Permanently?")) {
      setTransactions(prev => prev.filter(t => t.id !== id));
      if (editingTransaction?.id === id) setEditingTransaction(null);
    }
  };

  const startEditing = (t: Transaction) => {
    setEditingTransaction(t);
    setPreselectedCategory(null);
    const formEl = document.getElementById('transaction-form');
    if (formEl) formEl.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const updateBudget = (category: Category, amount: number) => {
    setBudgets(prev => ({ ...prev, [category]: amount }));
  };

  const addCustomCategory = (cat: CategoryConfig) => setCustomCategories(prev => [...prev, cat]);

  const updateCustomCategory = (updatedCat: CategoryConfig) => {
    const oldCat = customCategories.find(c => c.id === updatedCat.id);
    if (oldCat && oldCat.name !== updatedCat.name) {
      setTransactions(prev => prev.map(t => t.category === oldCat.name ? { ...t, category: updatedCat.name } : t));
      setBudgets(prev => {
        const newBudgets = { ...prev };
        if (newBudgets[oldCat.name]) {
          newBudgets[updatedCat.name] = newBudgets[oldCat.name];
          delete newBudgets[oldCat.name];
        }
        return newBudgets;
      });
    }
    setCustomCategories(prev => prev.map(c => c.id === updatedCat.id ? updatedCat : c));
  };

  const deleteCustomCategory = (id: string) => {
    const catToDelete = customCategories.find(c => c.id === id);
    if (catToDelete) {
      const defaultName = catToDelete.type === TransactionType.INCOME ? 'Daily Income' : catToDelete.type === TransactionType.SAVINGS ? 'Savings' : 'Others';
      setTransactions(prev => prev.map(t => t.category === catToDelete.name ? { ...t, category: defaultName } : t));
    }
    setCustomCategories(prev => prev.filter(c => c.id !== id));
  };

  const clearAll = () => { if (window.confirm("Delete All Data? This Cannot Be Undone.")) setTransactions([]); };

  const todayStr = useMemo(() => new Date().toISOString().split('T')[0], []);
  const currentMonthStr = useMemo(() => new Date().toISOString().substring(0, 7), []);
  const firstOfCurrentMonth = currentMonthStr + "-01";

  const filterByPreset = (txs: Transaction[], preset: DatePreset) => {
    const now = new Date();
    const today = now.toISOString().split('T')[0];
    return txs.filter(t => {
      switch (preset) {
        case 'today': return t.date === today;
        case 'yesterday': {
          const y = new Date(now);
          y.setDate(now.getDate() - 1);
          return t.date === y.toISOString().split('T')[0];
        }
        case 'last7': {
          const l7 = new Date(now);
          l7.setDate(now.getDate() - 7);
          return t.date >= l7.toISOString().split('T')[0];
        }
        case 'thisMonth': return t.date.startsWith(now.toISOString().substring(0, 7));
        case 'lastMonth': {
          const lm = new Date(now.getFullYear(), now.getMonth() - 1, 1);
          return t.date.startsWith(lm.toISOString().substring(0, 7));
        }
        case 'thisYear': return t.date.startsWith(now.getFullYear().toString());
        default: return true;
      }
    });
  };

  const summary = useMemo(() => {
    let opening: number = 0;
    let monthlyIncome: number = 0;
    let monthlyExpenses: number = 0;
    let monthlySavings: number = 0;
    let liquidBalance: number = 0;
    let totalSavingsBalance: number = 0;
    let todayExp: number = 0;
    let todayInc: number = 0;
    let cumulativeInc: number = 0;

    transactions.forEach(t => {
      const amount = Number(t.amount) || 0;
      const isToday = t.date === todayStr;
      const isCurrentMonth = t.date.startsWith(currentMonthStr);
      const isBeforeCurrentMonth = t.date < firstOfCurrentMonth;
      const isOpeningCategory = t.category === 'Opening Balance';

      // GLOBAL BALANCE CALCULATION (CASH IN HAND)
      if (t.type === TransactionType.INCOME) {
        liquidBalance += amount;
        cumulativeInc += amount;
      } else if (t.type === TransactionType.EXPENSE) {
        liquidBalance -= amount;
      } else if (t.type === TransactionType.SAVINGS) {
        liquidBalance -= amount;
        totalSavingsBalance += amount;
      }

      // DYNAMIC OPENING BALANCE
      // Now includes anything categorized as 'Opening Balance' regardless of date
      if (isBeforeCurrentMonth || isOpeningCategory) {
        if (t.type === TransactionType.INCOME) opening += amount;
        else if (t.type === TransactionType.EXPENSE) opening -= amount;
        else if (t.type === TransactionType.SAVINGS) opening -= amount;
      }

      // MONTHLY TOTALS
      if (isCurrentMonth) {
        // We exclude 'Opening Balance' from Monthly Income as it's a baseline, not recurring revenue
        if (t.type === TransactionType.INCOME && !isOpeningCategory) {
          monthlyIncome += amount;
          if (isToday) todayInc += amount;
        } else if (t.type === TransactionType.EXPENSE) {
          monthlyExpenses += amount;
          if (isToday) todayExp += amount;
        } else if (t.type === TransactionType.SAVINGS) {
          monthlySavings += amount;
        }
      }
    });

    const totalBudgetValue = (Object.values(budgets) as number[]).reduce((sum: number, val: number) => sum + (Number(val) || 0), 0);

    return { 
      openingBalance: opening, 
      totalIncome: monthlyIncome, 
      totalExpenses: monthlyExpenses, 
      currentBalance: liquidBalance, 
      todayExpenses: todayExp, 
      todayIncome: todayInc, 
      cumulativeIncome: cumulativeInc, 
      totalBudget: totalBudgetValue,
      totalSavings: totalSavingsBalance
    };
  }, [transactions, todayStr, currentMonthStr, firstOfCurrentMonth, budgets]);

  const monthlySpending = useMemo(() => {
    const spendingMap: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.type === TransactionType.EXPENSE && t.date.startsWith(currentMonthStr)) {
        spendingMap[t.category] = (spendingMap[t.category] || 0) + (Number(t.amount) || 0);
      }
    });
    return spendingMap;
  }, [transactions, currentMonthStr]);

  const budgetUsagePercent = Math.min((summary.totalExpenses / (summary.totalBudget || 1)) * 100, 100);
  const formatCurrency = (val: number) => new Intl.NumberFormat(undefined, { minimumFractionDigits: 2 }).format(val);

  const handleQuickAdd = (categoryName: string) => {
    setPreselectedCategory(categoryName);
    setEditingTransaction(null);
    const formEl = document.getElementById('transaction-form');
    if (formEl) formEl.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const quickExpenseCategories = ['Food', 'Fuel', 'Bike Repair', 'Parcel', 'Mobile Top Up', 'Data Top Up', 'Tea', 'Buy Accessories', 'Others'];
  const quickIncomeCategories = ['Daily Income', 'Opening Balance'];

  const navItems = [
    { id: 'overview', label: 'Overview', icon: LayoutDashboard },
    { id: 'income', label: 'Income', icon: ArrowUpCircle },
    { id: 'expenses', label: 'Expenses', icon: Zap },
    { id: 'savings', label: 'Savings', icon: PiggyBank },
    { id: 'budget', label: 'Budgets', icon: Target },
    { id: 'reports', label: 'Reports', icon: FileText },
    { id: 'settings', label: 'Settings', icon: Settings }
  ];

  const LedgerView = ({ type, title, colorClass, pillClass, onEdit, onDelete }: { 
    type: TransactionType, 
    title: string, 
    colorClass: string, 
    pillClass: string,
    onEdit: (t: Transaction) => void,
    onDelete: (id: string) => void
  }) => {
    const filteredTxs = filterByPreset(transactions.filter(t => t.type === type), ledgerDateFilter);

    return (
      <div className="bg-white rounded-2xl md:rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden flex flex-col h-full md:max-h-[750px]">
        <div className="p-5 md:p-8 border-b border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div className="flex flex-col">
            <h3 className={`text-base md:text-2xl font-black ${colorClass} capitalize`}>{title}</h3>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">Historical Audit Trail</p>
          </div>
          <DateDropdown value={ledgerDateFilter} onChange={setLedgerDateFilter} />
        </div>
        <div className="overflow-auto scrollbar-hide">
          <table className="hidden md:table w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr className="text-[9px] font-black text-slate-500 uppercase tracking-widest">
                <th className="px-8 py-5">Value Date</th>
                <th className="px-8 py-5">Category Context</th>
                <th className="px-8 py-5 text-right">Settled Value</th>
                <th className="px-8 py-5 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTxs.length > 0 ? filteredTxs.map(t => (
                <tr key={t.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-8 py-6">
                    <span className="bg-slate-100 px-3 py-1.5 rounded-full text-xs font-black text-slate-600 border border-slate-200">{t.date}</span>
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex flex-col">
                      <span className="font-black text-slate-800 text-base capitalize">{t.category}</span>
                      {t.note !== t.category && <span className="text-[10px] text-slate-400 font-bold italic truncate max-w-[200px]">{t.note}</span>}
                    </div>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <span className={`inline-block ${pillClass} px-5 py-2 rounded-full font-black text-base tracking-tight border tabular-nums shadow-sm text-slate-900`}>
                      RS{t.amount.toFixed(2)}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => onEdit(t)} className="p-2 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all">
                        <Edit3 className="w-4 h-4" />
                      </button>
                      <button onClick={() => onDelete(t.id)} className="p-2 text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={4} className="px-8 py-20 text-center">
                    <p className="text-slate-300 font-black uppercase text-[10px] tracking-widest">No entries found for this period</p>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
          <div className="md:hidden divide-y divide-slate-100">
            {filteredTxs.map(t => (
              <div key={t.id} className="p-5 space-y-3 active:bg-slate-50 transition-colors">
                <div className="flex items-center justify-between">
                  <div className="flex flex-col gap-1.5">
                    <span className="bg-slate-100 px-2.5 py-0.5 rounded-full text-[9px] font-black text-slate-500 w-fit">{t.date}</span>
                    <span className="text-base font-black text-slate-800 capitalize">{t.category}</span>
                  </div>
                  <span className={`${pillClass} px-4 py-2 rounded-full text-base font-black tracking-tighter border tabular-nums shadow-sm text-slate-900`}>
                    RS{t.amount.toFixed(2)}
                  </span>
                </div>
                <div className="flex items-center justify-end gap-4 pt-1">
                   <button onClick={() => onEdit(t)} className="flex items-center gap-1.5 text-[10px] font-black text-slate-400 hover:text-emerald-600">
                      <Edit3 className="w-3.5 h-3.5" /> Edit
                   </button>
                   <button onClick={() => onDelete(t.id)} className="flex items-center gap-1.5 text-[10px] font-black text-slate-400 hover:text-rose-500">
                      <Trash2 className="w-3.5 h-3.5" /> Remove
                   </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-24 md:pb-8 font-['Bahnschrift_SemiBold','Bahnschrift',sans-serif] overflow-x-hidden">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
