const EMOJI_MAP: Record<string, string> = {
  Fuel: '⛽', Wrench: '🔧', Utensils: '🍴', Coffee: '☕', Smartphone: '📱',
  Globe: '🌐', Package: '📦', Bike: '🚲', ShoppingBag: '🛍️', PlusCircle: '➕',
