    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${totalExp}</Data></Cell>
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.available}</Data></Cell>
   </Row>`;
    });

    xml += `
