// Define explicit interface for day summary to avoid 'any' and 'unknown' indexing issues
interface LedgerDay {
  date: string;
  income: number;
  expenses: number;
  savings: number;
  available: number;
  categories: Record<string, number>;
}

interface ReportViewProps {
  transactions: Transaction[];
  summary: DailySummary;
  customCategories: CategoryConfig[];
  budgets: Record<string, number>;
}

const ReportView: React.FC<ReportViewProps> = ({ transactions, summary, customCategories }) => {
  const todayStr = new Date().toISOString().split('T')[0];

  const [datePreset, setDatePreset] = useState<DatePreset>('thisMonth');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>(todayStr);
  const [typeFilter, setTypeFilter] = useState<'ALL' | TransactionType>('ALL');

  useEffect(() => {
    const now = new Date();
    let start = '';
    let end = todayStr;

    switch (datePreset) {
      case 'today':
        start = todayStr;
        break;
      case 'yesterday':
        const yesterday = new Date(now);
        yesterday.setDate(now.getDate() - 1);
        start = yesterday.toISOString().split('T')[0];
        end = start;
        break;
      case 'last7':
        const last7 = new Date(now);
        last7.setDate(now.getDate() - 7);
        start = last7.toISOString().split('T')[0];
        break;
      case 'thisMonth':
        start = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
        break;
      case 'lastMonth':
        const firstOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
        const lastOfLastMonth = new Date(now.getFullYear(), now.getMonth(), 0);
        start = firstOfLastMonth.toISOString().split('T')[0];
        end = lastOfLastMonth.toISOString().split('T')[0];
        break;
      case 'all':
        start = '';
        break;
    }

    setStartDate(start);
    setEndDate(end);
  }, [datePreset, todayStr]);

  const escapeXML = (str: any) => {
    if (str === null || str === undefined) return '';
    return str.toString()
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&apos;');
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat(undefined, { 
    minimumFractionDigits: 2, 
    maximumFractionDigits: 2 
  }).format(val);

  const periodTransactions = useMemo(() => {
    return transactions.filter(t => {
      let matchesDate = true;
      if (startDate) matchesDate = t.date >= startDate;
      if (matchesDate && endDate) matchesDate = matchesDate && t.date <= endDate;

      if (!matchesDate) return false;
      if (typeFilter !== 'ALL' && t.type !== typeFilter) return false;

      return true;
    }).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, startDate, endDate, typeFilter]);

  const ledgerData = useMemo(() => {
    const filtered = transactions.filter(t => {
      if (startDate && t.date < startDate) return false;
      if (endDate && t.date > endDate) return false;
      return true;
    });

    const dates = Array.from(new Set(filtered.map(t => t.date))).sort().reverse() as string[];
    let cumulative = 0;

    // Sort ascending for cumulative calc then reverse back
    const sortedDates = [...dates].sort();
    const daySummaries: Record<string, LedgerDay> = {};

    sortedDates.forEach(date => {
      const dayTxs = filtered.filter(t => t.date === date);
      const inc = dayTxs.filter(t => t.type === TransactionType.INCOME).reduce((s, t) => s + t.amount, 0);
      const exp = dayTxs.filter(t => t.type === TransactionType.EXPENSE).reduce((s, t) => s + t.amount, 0);
      const sav = dayTxs.filter(t => t.type === TransactionType.SAVINGS).reduce((s, t) => s + t.amount, 0);
      cumulative += (inc - exp - sav);

      const cats: Record<string, number> = {};
      // Fix: Ensure category name is treated as a string for safe indexing
      dayTxs.forEach(t => {
        const catName = String(t.category);
        cats[catName] = (cats[catName] || 0) + t.amount;
      });

      daySummaries[date] = { date, income: inc, expenses: exp, savings: sav, available: cumulative, categories: cats };
    });

    // Added type guard filter to ensure ledgerData contains only valid LedgerDay objects to fix unknown type issues
    return dates.map(date => daySummaries[date]).filter((d): d is LedgerDay => d !== undefined);
  }, [transactions, startDate, endDate]);

  const generateExcelXML = () => {
    const periodLabel = escapeXML(`${startDate || 'Full History'} to ${endDate}`);

    // Fix: Explicitly type category lists using 'as string[]' to resolve unknown type inference errors
    const incomeCats: string[] = Array.from(new Set(periodTransactions.filter(t => t.type === TransactionType.INCOME).map(t => t.category))).sort() as string[];
    const expenseCats: string[] = Array.from(new Set(periodTransactions.filter(t => t.type === TransactionType.EXPENSE).map(t => t.category))).sort() as string[];
    const savingsCats: string[] = Array.from(new Set(periodTransactions.filter(t => t.type === TransactionType.SAVINGS).map(t => t.category))).sort() as string[];

    let xml = `<?xml version="1.0" encoding="UTF-8"?><?mso-application progid="Excel.Sheet"?>
<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:o="urn:schemas-microsoft-com:office:office"
 xmlns:x="urn:schemas-microsoft-com:office:excel"
 xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:html="http://www.w3.org/TR/REC-html40">
 <Styles>
  <Style ss:ID="Default" ss:Name="Normal">
   <Alignment ss:Vertical="Bottom"/>
   <Borders/>
   <Font ss:FontName="Segoe UI" ss:Size="11" ss:Color="#1E293B"/>
  </Style>
  <Style ss:ID="HeaderStyle">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#FFFFFF"/>
   <Interior ss:Color="#334155" ss:Pattern="Solid"/>
   <Alignment ss:Horizontal="Center" ss:Vertical="Center"/>
  </Style>
  <Style ss:ID="IncomeHeader">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#FFFFFF"/>
   <Interior ss:Color="#10B981" ss:Pattern="Solid"/>
  </Style>
  <Style ss:ID="ExpenseHeader">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#FFFFFF"/>
   <Interior ss:Color="#F43F5E" ss:Pattern="Solid"/>
  </Style>
  <Style ss:ID="SavingsHeader">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#FFFFFF"/>
   <Interior ss:Color="#6366F1" ss:Pattern="Solid"/>
  </Style>
  <Style ss:ID="Currency">
   <NumberFormat ss:Format="&quot;RS&quot;#,##0.00"/>
  </Style>
  <Style ss:ID="BoldText">
   <Font ss:FontName="Segoe UI" ss:Bold="1"/>
  </Style>
 </Styles>

 <Worksheet ss:Name="Daily Categorical Analysis">
  <Table ss:DefaultColumnWidth="120">
   <Row ss:Height="25">
    <Cell ss:StyleID="HeaderStyle"><Data ss:Type="String">Date</Data></Cell>
    ${incomeCats.map((c: string) => `<Cell ss:StyleID="IncomeHeader"><Data ss:Type="String">${escapeXML(c)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="IncomeHeader"><Data ss:Type="String">Daily Income</Data></Cell>
    ${expenseCats.map((c: string) => `<Cell ss:StyleID="ExpenseHeader"><Data ss:Type="String">${escapeXML(c)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="ExpenseHeader"><Data ss:Type="String">Daily Expense</Data></Cell>
    ${savingsCats.map((c: string) => `<Cell ss:StyleID="SavingsHeader"><Data ss:Type="String">${escapeXML(c)}</Data></Cell>`).join('')}
    <Cell ss:StyleID="SavingsHeader"><Data ss:Type="String">Daily Savings</Data></Cell>
    <Cell ss:StyleID="HeaderStyle"><Data ss:Type="String">Cash in Hand</Data></Cell>
   </Row>`;

    ledgerData.forEach((day: LedgerDay) => {
      xml += `
   <Row>
    <Cell><Data ss:Type="String">${day.date}</Data></Cell>
    ${// Fix: Explicitly map using string index for categories to avoid unknown index type errors
    incomeCats.map((c: string) => `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.categories[c] || 0}</Data></Cell>`).join('')}
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.income}</Data></Cell>
    ${// Fix: Explicitly map using string index for categories to avoid unknown index type errors
    expenseCats.map((c: string) => `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.categories[c] || 0}</Data></Cell>`).join('')}
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.expenses}</Data></Cell>
    ${// Fix: Explicitly map using string index for categories to avoid unknown index type errors
    savingsCats.map((c: string) => `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.categories[c] || 0}</Data></Cell>`).join('')}
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.savings}</Data></Cell>
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${day.available}</Data></Cell>
   </Row>`;
    });

    xml += `
  </Table>
 </Worksheet>

 <Worksheet ss:Name="Detailed Transaction Log">
  <Table ss:DefaultColumnWidth="140">
   <Row ss:Height="25">
    <Cell ss:StyleID="HeaderStyle"><Data ss:Type="String">Date</Data></Cell>
    <Cell ss:StyleID="HeaderStyle"><Data ss:Type="String">Type</Data></Cell>
    <Cell ss:StyleID="HeaderStyle"><Data ss:Type="String">Category</Data></Cell>
    <Cell ss:StyleID="HeaderStyle"><Data ss:Type="String">Amount</Data></Cell>
    <Cell ss:StyleID="HeaderStyle"><Data ss:Type="String">Details</Data></Cell>
   </Row>`;

    periodTransactions.slice().reverse().forEach(t => {
      xml += `
   <Row>
    <Cell><Data ss:Type="String">${t.date}</Data></Cell>
    <Cell><Data ss:Type="String">${t.type}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXML(t.category)}</Data></Cell>
    <Cell ss:StyleID="Currency"><Data ss:Type="Number">${t.amount}</Data></Cell>
    <Cell><Data ss:Type="String">${escapeXML(t.note)}</Data></Cell>
   </Row>`;
    });

    xml += `
  </Table>
 </Worksheet>
</Workbook>`;

    const blob = new Blob([xml], { type: 'application/vnd.ms-excel' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `SpendWise_Matrix_Report_${startDate || 'all'}_to_${endDate}.xls`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="space-y-8 pb-12 animate-in fade-in slide-in-from-bottom-2 duration-500">
      <div className="bg-white p-6 md:p-8 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-3 rounded-2xl">
            <FileSpreadsheet className="w-6 h-6 text-white" />
          </div>
          <div>
            <h2 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight capitalize">Full Analytical Report</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Multi-Sheet Matrix Export</p>
          </div>
        </div>
        <button 
          onClick={generateExcelXML} 
          className="flex items-center gap-2 bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black text-sm hover:bg-emerald-700 transition-all active:scale-95 shadow-xl shadow-emerald-100 justify-center"
        >
          <FileSpreadsheet className="w-5 h-5" />
          Generate Excel Matrix (.xls)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 text-blue-600 mb-2">
            <Landmark className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Opening Bal.</span>
          </div>
          <p className="text-2xl font-black text-slate-900 tracking-tight">RS{formatCurrency(summary.openingBalance)}</p>
        </div>
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 text-emerald-600 mb-2">
            <ArrowUpCircle className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Income</span>
          </div>
          <p className="text-2xl font-black text-slate-900 tracking-tight">RS{formatCurrency(summary.totalIncome)}</p>
        </div>
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 text-rose-600 mb-2">
            <Zap className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Expenses</span>
          </div>
          <p className="text-2xl font-black text-slate-900 tracking-tight">RS{formatCurrency(summary.totalExpenses)}</p>
        </div>
        <div className="bg-indigo-600 p-6 rounded-[2rem] border border-indigo-500 shadow-xl shadow-indigo-100">
          <div className="flex items-center gap-2 text-indigo-100 mb-2">
            <TrendingDown className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Cash in Hand</span>
          </div>
          <p className="text-2xl font-black text-white tracking-tight">RS{formatCurrency(summary.currentBalance)}</p>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-2">
            <Table className="w-5 h-5 text-slate-400" />
            <h3 className="font-black text-slate-800 text-sm uppercase tracking-widest">Ledger Preview</h3>
          </div>
          <DateDropdown value={datePreset} onChange={setDatePreset} />
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 text-[10px] uppercase font-black text-slate-400 tracking-widest border-b border-slate-100">
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4 text-right">Day Income</th>
                <th className="px-6 py-4 text-right">Day Expenses</th>
                <th className="px-6 py-4 text-right">Day Savings</th>
                <th className="px-6 py-4 text-right">Cash in Hand</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {ledgerData.map((day: LedgerDay, i: number) => (
                <tr key={i} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4 text-xs font-black text-slate-500">{day.date}</td>
                  <td className="px-6 py-4 text-right text-sm font-black text-emerald-600">+{day.income.toFixed(2)}</td>
                  <td className="px-6 py-4 text-right text-sm font-black text-rose-500">-{day.expenses.toFixed(2)}</td>
                  <td className="px-6 py-4 text-right text-sm font-black text-indigo-500">-{day.savings.toFixed(2)}</td>
                  <td className="px-6 py-4 text-right">
                    <span className="bg-slate-100 px-3 py-1 rounded-full text-xs font-black text-slate-900">
                      {day.available.toFixed(2)}
                    </span>
                  </td>
                </tr>
              ))}
              {ledgerData.length === 0 && (
                <tr><td colSpan={5} className="py-20 text-center text-slate-300 font-bold capitalize">No data for this period.</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ReportView;

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, TransactionType, Category, DailySummary, CategoryConfig } from './types';
import { DEFAULT_CATEGORIES, getCategoryConfig, ICON_MAP } from './constants';
import TransactionForm from './components/TransactionForm';
import Stats from './components/Stats';
import Charts from './components/Charts';
import AIAssistant from './components/AIAssistant';
import ReportView from './components/ReportView';
import BudgetManager from './components/BudgetManager';
import BudgetProgress from './components/BudgetProgress';
import CategoryManager from './components/CategoryManager';
import CompoundSavings from './components/CompoundSavings';
import DateDropdown, { DatePreset } from './components/DateDropdown';
import { Trash2, Wallet, LayoutDashboard, FileText, Target, ArrowUpCircle, MoreHorizontal, Zap, Settings, Sparkles, PiggyBank, Edit3, PlusCircle } from 'lucide-react';

type TabType = 'overview' | 'income' | 'expenses' | 'savings' | 'reports' | 'budget' | 'settings';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('overview');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [ledgerDateFilter, setLedgerDateFilter] = useState<DatePreset>('all');
  const [preselectedCategory, setPreselectedCategory] = useState<string | null>(null);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('spendwise_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [budgets, setBudgets] = useState<Record<string, number>>(() => {
    const saved = localStorage.getItem('spendwise_budgets');
    return saved ? JSON.parse(saved) : {};
  });

  const [customCategories, setCustomCategories] = useState<CategoryConfig[]>(() => {
    const saved = localStorage.getItem('spendwise_custom_categories');
    return saved ? JSON.parse(saved) : [];
  });

  const [accounts, setAccounts] = useState<string[]>(() => {
    const saved = localStorage.getItem('spendwise_bank_accounts');
    return saved ? JSON.parse(saved) : ['Commercial Bank', 'Amana Bank'];
  });

  useEffect(() => {
    localStorage.setItem('spendwise_transactions', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('spendwise_budgets', JSON.stringify(budgets));
  }, [budgets]);

  useEffect(() => {
    localStorage.setItem('spendwise_custom_categories', JSON.stringify(customCategories));
  }, [customCategories]);

  useEffect(() => {
    localStorage.setItem('spendwise_bank_accounts', JSON.stringify(accounts));
  }, [accounts]);

  const toTitleCase = (str: string) => str.toLowerCase().split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

  const addAccount = (name: string) => {
    const titleCased = toTitleCase(name);
    if (!accounts.includes(titleCased)) {
      setAccounts(prev => [...prev, titleCased]);
    }
  };

  const saveTransaction = (newTransaction: Transaction) => {
    setTransactions(prev => {
      if (editingTransaction) {
        setEditingTransaction(null);
        return prev.map(t => t.id === newTransaction.id ? newTransaction : t);
      }
      return [newTransaction, ...prev];
    });
    setPreselectedCategory(null);
  };

  const removeTransaction = (id: string) => {
    if (window.confirm("Remove This Entry Permanently?")) {
      setTransactions(prev => prev.filter(t => t.id !== id));
      if (editingTransaction?.id === id) setEditingTransaction(null);
    }
  };

  const startEditing = (t: Transaction) => {
    setEditingTransaction(t);
    setPreselectedCategory(null);
    const formEl = document.getElementById('transaction-form');
    if (formEl) formEl.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const updateBudget = (category: Category, amount: number) => {
    setBudgets(prev => ({ ...prev, [category]: amount }));
  };

  const addCustomCategory = (cat: CategoryConfig) => setCustomCategories(prev => [...prev, cat]);

  const updateCustomCategory = (updatedCat: CategoryConfig) => {
    const oldCat = customCategories.find(c => c.id === updatedCat.id);
    if (oldCat && oldCat.name !== updatedCat.name) {
      setTransactions(prev => prev.map(t => t.category === oldCat.name ? { ...t, category: updatedCat.name } : t));
      setBudgets(prev => {
        const newBudgets = { ...prev };
        if (newBudgets[oldCat.name]) {
          newBudgets[updatedCat.name] = newBudgets[oldCat.name];
          delete newBudgets[oldCat.name];
        }
        return newBudgets;
      });
    }
    setCustomCategories(prev => prev.map(c => c.id === updatedCat.id ? updatedCat : c));
  };

  const deleteCustomCategory = (id: string) => {
    const catToDelete = customCategories.find(c => c.id === id);
    if (catToDelete) {
      const defaultName = catToDelete.type === TransactionType.INCOME ? 'Daily Income' : catToDelete.type === TransactionType.SAVINGS ? 'Savings' : 'Others';
      setTransactions(prev => prev.map(t => t.category === catToDelete.name ? { ...t, category: defaultName } : t));
    }
    setCustomCategories(prev => prev.filter(c => c.id !== id));
  };

  const clearAll = () => { if (window.confirm("Delete All Data? This Cannot Be Undone.")) setTransactions([]); };

  // Use local date string (en-CA returns YYYY-MM-DD reliably)
  const todayStr = new Date().toLocaleDateString('en-CA');
  const currentMonthStr = todayStr.substring(0, 7);
  const firstOfCurrentMonth = currentMonthStr + "-01";

  const filterByPreset = (txs: Transaction[], preset: DatePreset) => {
    const now = new Date();
    const today = now.toLocaleDateString('en-CA');
    return txs.filter(t => {
      switch (preset) {
        case 'today': return t.date === today;
        case 'yesterday': {
          const y = new Date(now);
          y.setDate(now.getDate() - 1);
          return t.date === y.toLocaleDateString('en-CA');
        }
        case 'last7': {
          const l7 = new Date(now);
          l7.setDate(now.getDate() - 7);
          return t.date >= l7.toLocaleDateString('en-CA');
        }
        case 'thisMonth': return t.date.startsWith(now.toLocaleDateString('en-CA').substring(0, 7));
        case 'lastMonth': {
          const lm = new Date(now.getFullYear(), now.getMonth() - 1, 1);
          return t.date.startsWith(lm.toLocaleDateString('en-CA').substring(0, 7));
        }
        case 'thisYear': return t.date.startsWith(now.getFullYear().toString());
        default: return true;
      }
    });
  };

  const summary = useMemo(() => {
    let opening: number = 0;
    let monthlyIncome: number = 0;
    let monthlyExpenses: number = 0;
    let monthlySavings: number = 0;
    let liquidBalance: number = 0;
    let totalSavingsBalance: number = 0;
    let todayExp: number = 0;
    let todayInc: number = 0;
    let cumulativeInc: number = 0;

    transactions.forEach(t => {
      const amount = Number(t.amount) || 0;
      const isToday = t.date === todayStr;
      const isCurrentMonth = t.date.startsWith(currentMonthStr);
      const isBeforeCurrentMonth = t.date < firstOfCurrentMonth;
      const isOpeningCategory = t.category === 'Opening Balance';

      // GLOBAL BALANCE CALCULATION (CASH IN HAND)
      if (t.type === TransactionType.INCOME) {
        liquidBalance += amount;
        cumulativeInc += amount;
      } else if (t.type === TransactionType.EXPENSE) {
        liquidBalance -= amount;
      } else if (t.type === TransactionType.SAVINGS) {
        liquidBalance -= amount;
        totalSavingsBalance += amount;
      }

      // DYNAMIC OPENING BALANCE
      if (isBeforeCurrentMonth || isOpeningCategory) {
        if (t.type === TransactionType.INCOME) opening += amount;
        else if (t.type === TransactionType.EXPENSE) opening -= amount;
        else if (t.type === TransactionType.SAVINGS) opening -= amount;
      }

      // MONTHLY TOTALS
      if (isCurrentMonth) {
        if (t.type === TransactionType.INCOME && !isOpeningCategory) {
          monthlyIncome += amount;
          if (isToday) todayInc += amount;
        } else if (t.type === TransactionType.EXPENSE) {
          monthlyExpenses += amount;
          if (isToday) todayExp += amount;
        } else if (t.type === TransactionType.SAVINGS) {
          monthlySavings += amount;
        }
      } else {
        if (isToday) {
           if (t.type === TransactionType.INCOME && !isOpeningCategory) todayInc += amount;
           else if (t.type === TransactionType.EXPENSE) todayExp += amount;
        }
      }
    });

    const totalBudgetValue = (Object.values(budgets) as number[]).reduce((sum: number, val: number) => sum + (Number(val) || 0), 0);

    return { 
      openingBalance: opening, 
      totalIncome: monthlyIncome, 
      totalExpenses: monthlyExpenses, 
      currentBalance: liquidBalance, 
      todayExpenses: todayExp,
      todayIncome: todayInc,
      cumulativeIncome: cumulativeInc,
      totalBudget: totalBudgetValue,
      totalSavings: totalSavingsBalance
    };
  }, [transactions, budgets, todayStr, currentMonthStr, firstOfCurrentMonth]);

  const filteredTransactions = useMemo(() => {
    let filtered = transactions;
    if (activeTab === 'income') filtered = transactions.filter(t => t.type === TransactionType.INCOME);
    if (activeTab === 'expenses') filtered = transactions.filter(t => t.type === TransactionType.EXPENSE);
    if (activeTab === 'savings') filtered = transactions.filter(t => t.type === TransactionType.SAVINGS);

    return filterByPreset(filtered, ledgerDateFilter);
  }, [transactions, activeTab, ledgerDateFilter]);

  const monthlySpending = useMemo(() => {
    const spending: Record<string, number> = {};
    transactions.forEach(t => {
      if (t.type === TransactionType.EXPENSE && t.date.startsWith(currentMonthStr)) {
        spending[t.category] = (spending[t.category] || 0) + t.amount;
      }
    });
    return spending;
  }, [transactions, currentMonthStr]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900 selection:bg-emerald-100 selection:text-emerald-900">
      <nav className="sticky top-0 z-[100] bg-white/80 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8">
        <div className="max-w-7xl mx-auto flex items-center justify-between h-20">
