import React, { useMemo, useState, useEffect } from 'react';
import { 
  FileSpreadsheet, 
  Table, 
  CalendarDays, 
  TrendingDown, 
  FileText, 
  Filter, 
  ArrowRightLeft, 
  PiggyBank, 
  Landmark,
  PieChart as PieChartIcon,
  Zap,
  ArrowUpCircle,
  ChevronDown,
  Calendar,
  Loader2
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell
} from 'recharts';
import { Transaction, DailySummary, TransactionType, CategoryConfig } from '../types';
import { getCategoryConfig } from '../constants';
import DateDropdown, { DatePreset } from './DateDropdown';

interface LedgerDay {
  date: string;
  income: number;
  expenses: number;
  savings: number;
  available: number;
  categories: Record<string, number>;
}

interface ReportViewProps {
  transactions: Transaction[];
  summary: DailySummary;
  customCategories: CategoryConfig[];
  budgets: Record<string, number>;
}

const ReportView: React.FC<ReportViewProps> = ({ transactions, summary, customCategories }) => {
  const todayStr = new Date().toISOString().split('T')[0];

  const [datePreset, setDatePreset] = useState<DatePreset>('thisMonth');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>(todayStr);
  const [typeFilter, setTypeFilter] = useState<'ALL' | TransactionType>('ALL');
  const [isGenerating, setIsGenerating] = useState(false);

  useEffect(() => {
    const now = new Date();
    let start = '';
    let end = todayStr;

    switch (datePreset) {
      case 'today':
        start = todayStr;
        end = todayStr;
        break;
      case 'yesterday':
        const yesterday = new Date(now);
        yesterday.setDate(now.getDate() - 1);
        start = yesterday.toISOString().split('T')[0];
        end = start;
        break;
      case 'last7':
        const last7 = new Date(now);
        last7.setDate(now.getDate() - 7);
        start = last7.toISOString().split('T')[0];
        end = todayStr;
        break;
      case 'thisMonth':
        start = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
        end = todayStr;
        break;
      case 'lastMonth':
        const firstOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
        const lastOfLastMonth = new Date(now.getFullYear(), now.getMonth(), 0);
        start = firstOfLastMonth.toISOString().split('T')[0];
        end = lastOfLastMonth.toISOString().split('T')[0];
        break;
      case 'all':
        start = '';
        end = todayStr;
        break;
      case 'custom':
        if (!startDate) {
          setStartDate(new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0]);
        }
        return;
    }

    setStartDate(start);
    setEndDate(end);
  }, [datePreset, todayStr]);

  const escapeXML = (str: any) => {
    if (str === null || str === undefined) return '';
    return str.toString()
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&apos;');
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat(undefined, { 
    minimumFractionDigits: 2, 
    maximumFractionDigits: 2 
  }).format(val);

  const periodTransactions = useMemo(() => {
    return transactions.filter(t => {
      let matchesDate = true;
      if (startDate) matchesDate = t.date >= startDate;
      if (matchesDate && endDate) matchesDate = matchesDate && t.date <= endDate;

      if (!matchesDate) return false;
      if (typeFilter !== 'ALL' && t.type !== typeFilter) return false;

      return true;
    }).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, startDate, endDate, typeFilter]);

  const ledgerData = useMemo(() => {
    const allDates: string[] = Array.from(new Set(transactions.map(t => t.date))).sort() as string[];
    const ledgerMap: Record<string, LedgerDay> = {};
    let runningBalance = 0;

    allDates.forEach((date: string) => {
      const dayTxs = transactions.filter(t => t.date === date);
      const dayIncome = dayTxs.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
      const dayExpenses = dayTxs.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
      const daySavings = dayTxs.filter(t => t.type === TransactionType.SAVINGS).reduce((sum, t) => sum + t.amount, 0);

      const catBreakdown: Record<string, number> = {};
      dayTxs.forEach((t: Transaction) => {
        catBreakdown[t.category] = (catBreakdown[t.category] || 0) + t.amount;
      });

      runningBalance += dayIncome - dayExpenses - daySavings;

      ledgerMap[date] = { 
        date, 
        income: dayIncome, 
        expenses: dayExpenses,
        savings: daySavings,
        available: runningBalance,
        categories: catBreakdown
      };
    });

    return Object.keys(ledgerMap)
      .filter(date => {
        let matches = true;
        if (startDate) matches = date >= startDate;
        if (matches && endDate) matches = matches && date <= endDate;
        return matches;
      })
      .sort((a, b) => b.localeCompare(a))
      .map(date => ledgerMap[date])
      .filter((d): d is LedgerDay => d !== undefined);
  }, [transactions, startDate, endDate]);

  const fullPeriodSummary = useMemo(() => {
    let income = 0, expense = 0, savings = 0;
    periodTransactions.forEach(t => {
      if (t.type === TransactionType.INCOME && t.category !== 'Opening Balance') income += t.amount;
      else if (t.type === TransactionType.EXPENSE) expense += t.amount;
      else if (t.type === TransactionType.SAVINGS) savings += t.amount;
    });
    return { income, expense, savings, net: income - expense - savings };
  }, [periodTransactions]);

  const categoryConcentrationData = useMemo(() => {
    const dataMap: Record<string, { amount: number, color: string }> = {};
    periodTransactions
      .forEach(t => {
        if (!dataMap[t.category]) {
          const config = getCategoryConfig(t.category, customCategories);
          dataMap[t.category] = { amount: 0, color: config.color };
        }
        dataMap[t.category].amount += t.amount;
      });
    return Object.entries(dataMap)
      .map(([name, data]: [string, { amount: number, color: string }]) => ({
        name,
        amount: data.amount,
        color: data.color
      }))
      .sort((a, b) => b.amount - a.amount);
  }, [periodTransactions, customCategories]);

  const generateExcelXML = async () => {
    setIsGenerating(true);
    // Simulate generation delay for UX
    await new Promise(r => setTimeout(r, 800));

    const columns = [
      'Date', 
      'Opening Balance', 
      'Daily Income', 
      'Fuel', 
      'Bike', 
      'Bike Repair', 
      'Food', 
      'Tea', 
      'Mobile Topup', 
      'Internet Topup', 
      'Parcel', 
      'Buy Accessories', 
      'Savings', 
      'Others'
    ];

    const expenseCols = ['Fuel', 'Bike', 'Bike Repair', 'Food', 'Tea', 'Mobile Topup', 'Internet Topup', 'Parcel', 'Buy Accessories', 'Others'];

    const chronologicalLedger = [...ledgerData].sort((a, b) => a.date.localeCompare(b.date));

    const totals: Record<string, number> = {};
    columns.forEach(col => totals[col] = 0);

    let xml = `<?xml version="1.0" encoding="UTF-8"?><?mso-application progid="Excel.Sheet"?>
<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:o="urn:schemas-microsoft-com:office:office"
 xmlns:x="urn:schemas-microsoft-com:office:excel"
 xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet"
 xmlns:html="http://www.w3.org/TR/REC-html40">
 <Styles>
  <Style ss:ID="Default" ss:Name="Normal">
   <Alignment ss:Vertical="Bottom"/>
   <Borders/>
   <Font ss:FontName="Segoe UI" ss:Size="11" ss:Color="#1E293B"/>
  </Style>
  <Style ss:ID="HeaderStyle">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#000000"/>
   <Interior ss:Color="#E2E8F0" ss:Pattern="Solid"/>
   <Alignment ss:Horizontal="Center" ss:Vertical="Center"/>
   <Borders>
    <Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1"/>
    <Border ss:Position="Top" ss:LineStyle="Continuous" ss:Weight="1"/>
    <Border ss:Position="Left" ss:LineStyle="Continuous" ss:Weight="1"/>
    <Border ss:Position="Right" ss:LineStyle="Continuous" ss:Weight="1"/>
   </Borders>
  </Style>
  <Style ss:ID="GrandTotal">
   <Font ss:FontName="Segoe UI" ss:Bold="1" ss:Color="#000000"/>
   <Interior ss:Color="#CBD5E1" ss:Pattern="Solid"/>
   <Borders>
    <Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1"/>
    <Border ss:Position="Top" ss:LineStyle="Continuous" ss:Weight="1"/>
    <Border ss:Position="Left" ss:LineStyle="Continuous" ss:Weight="1"/>
    <Border ss:Position="Right" ss:LineStyle="Continuous" ss:Weight="1"/>
   </Borders>
  </Style>
  <Style ss:ID="BoldLabel">
   <Font ss:FontName="Segoe UI" ss:Bold="1"/>
  </Style>
  <Style ss:ID="Currency">
   <NumberFormat ss:Format="&quot;Rs &quot;#,##0.00"/>
   <Borders>
    <Border ss:Position="Bottom" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#E2E8F0"/>
    <Border ss:Position="Top" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#E2E8F0"/>
    <Border ss:Position="Left" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#E2E8F0"/>
    <Border ss:Position="Right" ss:LineStyle="Continuous" ss:Weight="1" ss:Color="#E2E8F0"/>
   </Borders>
  </Style>
  <Style ss:ID="SummaryHeader">
    <Font ss:FontName="Segoe UI" ss:Bold="1"/>
    <Interior ss:Color="#F1F5F9" ss:Pattern="Solid"/>
  </Style>
 </Styles>

 <Worksheet ss:Name="Daily Categorical Analysis">
  <Table ss:DefaultColumnWidth="120">
   <Row ss:Height="25">
    ${columns.map(col => `<Cell ss:StyleID="HeaderStyle"><Data ss:Type="String">${escapeXML(col)}</Data></Cell>`).join('')}
   </Row>`;

    chronologicalLedger.forEach((day: LedgerDay) => {
      xml += `<Row>`;
      columns.forEach(col => {
        let value: any = 0;
        if (col === 'Date') {
          value = day.date;
          xml += `<Cell><Data ss:Type="String">${escapeXML(value)}</Data></Cell>`;
          return;
        } else if (col === 'Opening Balance') {
          value = day.categories['Opening Balance'] || 0;
        } else if (col === 'Daily Income') {
          value = day.categories['Daily Income'] || 0;
        } else {
          value = day.categories[col] || 0;
        }

        totals[col] += value;
        xml += `<Cell ss:StyleID="Currency"><Data ss:Type="Number">${value}</Data></Cell>`;
      });
      xml += `</Row>`;
    });

    xml += `<Row ss:Height="20">
      <Cell ss:StyleID="GrandTotal"><Data ss:Type="String">GRAND TOTAL</Data></Cell>
      ${columns.slice(1).map(col => `<Cell ss:StyleID="GrandTotal" ss:StyleID="Currency"><Data ss:Type="Number">${totals[col]}</Data></Cell>`).join('')}
    </Row>`;

    xml += `<Row></Row><Row></Row>`;

    const totalOpening = totals['Opening Balance'];
    const totalInc = totals['Daily Income'];
    const totalExpOnly = expenseCols.reduce((sum, col) => sum + totals[col], 0);
    const totalSavings = totals['Savings'];
    const totalOutflow = totalExpOnly + totalSavings;
    const availBal = totalOpening + totalInc - totalOutflow;

    xml += `
    <Row><Cell ss:StyleID="SummaryHeader"><Data ss:Type="String">Final Summary</Data></Cell></Row>
    <Row>
      <Cell><Data ss:Type="String">Total Income</Data></Cell>
      <Cell ss:StyleID="Currency"><Data ss:Type="Number">${totalInc}</Data></Cell>
    </Row>
    <Row>
      <Cell><Data ss:Type="String">Total Expenses</Data></Cell>
      <Cell ss:StyleID="Currency"><Data ss:Type="Number">${totalOutflow}</Data></Cell>
    </Row>
    <Row>
      <Cell ss:StyleID="BoldLabel"><Data ss:Type="String">Available Balance</Data></Cell>
      <Cell ss:StyleID="Currency"><Data ss:Type="Number">${availBal}</Data></Cell>
    </Row>`;

    xml += `
  </Table>
 </Worksheet>
</Workbook>`;

    const blob = new Blob([xml], { type: 'application/vnd.ms-excel' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `SpendWise_Report_${startDate || 'all'}_to_${endDate}.xls`;
    link.click();
    URL.revokeObjectURL(url);
    setIsGenerating(false);
  };

  return (
    <div className="space-y-8 pb-12 animate-in fade-in slide-in-from-bottom-2 duration-500">
      <div className="bg-white p-6 md:p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-3 rounded-2xl shadow-lg shadow-emerald-200">
            <FileText className="w-6 h-6 text-white" />
          </div>
          <div>
            <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight capitalize">Financial Report Engine</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1 capitalize">Standard Matrix Excel Exports</p>
          </div>
        </div>
        <button 
          onClick={generateExcelXML} 
          disabled={isGenerating}
          className="flex items-center gap-2 bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black text-sm hover:bg-emerald-700 transition-all active:scale-95 shadow-xl shadow-emerald-100 capitalize w-full md:w-auto justify-center disabled:opacity-50"
        >
          {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <FileSpreadsheet className="w-5 h-5" />}
          {isGenerating ? 'Generating...' : 'Generate Excel Analysis'}
        </button>
      </div>

      <div className="bg-white p-6 md:p-8 rounded-[2.5rem] shadow-sm border border-slate-100 space-y-8">
        <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-6">
          <div className="flex flex-col gap-4">
            <div className="flex items-center gap-2">
              <Filter className="w-5 h-5 text-emerald-600" />
              <h3 className="font-black text-slate-800 uppercase tracking-[0.2em] text-[10px] capitalize">Contextual Filters</h3>
            </div>

            <div className="flex flex-wrap gap-3">
              <button onClick={() => setTypeFilter('ALL')} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all capitalize ${typeFilter === 'ALL' ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-400 border-slate-100 hover:border-slate-200'}`}>All Data</button>
              <button onClick={() => setTypeFilter(TransactionType.INCOME)} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all capitalize ${typeFilter === TransactionType.INCOME ? 'bg-emerald-600 text-white border-emerald-600' : 'bg-white text-emerald-400 border-slate-100 hover:border-emerald-100'}`}><ArrowUpCircle className="w-3.5 h-3.5" /> Income</button>
              <button onClick={() => setTypeFilter(TransactionType.EXPENSE)} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all capitalize ${typeFilter === TransactionType.EXPENSE ? 'bg-rose-500 text-white border-rose-500' : 'bg-white text-rose-400 border-slate-100 hover:border-rose-100'}`}><Zap className="w-3.5 h-3.5" /> Expenses</button>
              <button onClick={() => setTypeFilter(TransactionType.SAVINGS)} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all capitalize ${typeFilter === TransactionType.SAVINGS ? 'bg-teal-500 text-white border-teal-500' : 'bg-white text-teal-400 border-slate-100 hover:border-teal-100'}`}><PiggyBank className="w-3.5 h-3.5" /> Savings</button>
            </div>
          </div>

          <div className="flex flex-wrap gap-3 items-center bg-slate-50 p-4 rounded-[2.5rem] border border-slate-100 shadow-inner">
            <DateDropdown 
              value={datePreset}
              onChange={setDatePreset}
            />

            {datePreset === 'custom' && (
              <div className="flex items-center gap-3 animate-in slide-in-from-left-4 duration-500 ease-out">
                <div className="flex items-center gap-2 bg-white px-3 py-2 rounded-xl border border-slate-200 shadow-sm">
                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">From</span>
                  <div className="relative">
                    <Calendar className="absolute left-0 top-1/2 -translate-y-1/2 w-3 h-3 text-emerald-600 pointer-events-none" />
                    <input 
                      type="date" 
                      value={startDate} 
                      onChange={(e) => setStartDate(e.target.value)} 
                      className="pl-5 bg-transparent border-none p-0 text-xs font-black text-slate-700 outline-none focus:ring-0 w-28 uppercase" 
                    />
                  </div>
                </div>

                <ArrowRightLeft className="w-3.5 h-3.5 text-slate-300" />

                <div className="flex items-center gap-2 bg-white px-3 py-2 rounded-xl border border-slate-200 shadow-sm">
                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">To</span>
                  <div className="relative">
                    <Calendar className="absolute left-0 top-1/2 -translate-y-1/2 w-3 h-3 text-rose-500 pointer-events-none" />
                    <input 
                      type="date" 
                      value={endDate} 
                      onChange={(e) => setEndDate(e.target.value)} 
                      className="pl-5 bg-transparent border-none p-0 text-xs font-black text-slate-700 outline-none focus:ring-0 w-28 uppercase" 
                    />
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
          <div className="bg-emerald-50 p-6 rounded-[2rem] border border-emerald-100 transition-all hover:shadow-lg hover:shadow-emerald-100/50"><p className="text-[10px] font-black text-emerald-600 tracking-widest mb-1.5 capitalize">Opening Balance</p><p className="text-xl font-black text-emerald-700 tracking-tighter">RS{formatCurrency(summary.openingBalance)}</p></div>
          <div className="bg-rose-50 p-6 rounded-[2rem] border border-rose-100 transition-all hover:shadow-lg hover:shadow-rose-100/50"><p className="text-[10px] font-black text-rose-600 tracking-widest mb-1.5 capitalize">Period Outflow</p><p className="text-xl font-black text-rose-700 tracking-tighter">RS{formatCurrency(fullPeriodSummary.expense + fullPeriodSummary.savings)}</p></div>
          <div className="bg-teal-50 p-6 rounded-[2rem] border border-teal-100 transition-all hover:shadow-lg hover:shadow-teal-100/50"><p className="text-[10px] font-black text-teal-600 tracking-widest mb-1.5 capitalize">Period Savings</p><p className="text-xl font-black text-teal-700 tracking-tighter">RS{formatCurrency(fullPeriodSummary.savings)}</p></div>
          <div className="bg-blue-50 p-6 rounded-[2rem] border border-blue-100 transition-all hover:shadow-lg hover:shadow-blue-100/50"><p className="text-[10px] font-black text-blue-600 tracking-widest mb-1.5 capitalize">Net Cash Flow</p><p className="text-xl font-black text-blue-700 tracking-tighter">RS{formatCurrency(fullPeriodSummary.net)}</p></div>
          <div className="bg-indigo-50 p-6 rounded-[2rem] border border-indigo-100 transition-all hover:shadow-lg hover:shadow-indigo-100/50"><div className="flex items-center justify-between mb-1.5"><p className="text-[10px] font-black text-indigo-600 tracking-widest capitalize">Total Wealth</p><Landmark className="w-3.5 h-3.5 text-indigo-400" /></div><p className="text-xl font-black text-indigo-700 tracking-tighter">RS{formatCurrency(summary.currentBalance + summary.totalSavings)}</p></div>
        </div>

        <div className="pt-8 border-t border-slate-100">
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-slate-50 p-2.5 rounded-2xl border border-slate-200"><PieChartIcon className="w-5 h-5 text-slate-600" /></div>
            <div>
              <h3 className="text-lg font-black text-slate-800 tracking-tight capitalize">Category Concentration</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5 capitalize">Distribution Analysis For {typeFilter === 'ALL' ? 'Selected Period' : typeFilter}</p>
            </div>
          </div>
          <div className="h-[400px] w-full bg-slate-50/30 p-8 rounded-[3rem] border border-slate-100">
            {categoryConcentrationData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={categoryConcentrationData} layout="vertical" margin={{ left: 40, right: 40, top: 10, bottom: 10 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#e2e8f0" />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} width={120} tick={{ fontSize: 10, fontStyle: 'normal', fontWeight: 900, fill: '#64748b' }} />
                  <Tooltip cursor={{ fill: 'rgba(226, 232, 240, 0.4)' }} contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.1)', padding: '16px' }} formatter={(value: number) => [`RS${formatCurrency(value)}`, 'Total']} />
                  <Bar dataKey="amount" radius={[0, 12, 12, 0]} barSize={32}>
                    {categoryConcentrationData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 gap-4"><CalendarDays className="w-16 h-16 opacity-10" /><p className="text-sm font-black uppercase tracking-[0.2em] opacity-30 capitalize">No Categorical Data Found In This View</p></div>
            )}
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/30">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2.5 rounded-2xl border border-slate-200 shadow-sm"><Table className="w-5 h-5 text-emerald-600" /></div>
            <div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight capitalize">Financial Ledger (Live)</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-0.5 capitalize">True Running Balance Accounting</p>
            </div>
          </div>
          <div className="bg-white px-4 py-2 rounded-2xl border border-slate-200 shadow-sm"><span className="text-[10px] font-black text-slate-500 uppercase tracking-widest capitalize">{periodTransactions.length} Verified Entries</span></div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1000px]">
            <thead>
              <tr className="bg-slate-50 text-[10px] uppercase tracking-widest text-slate-500 font-black border-b border-slate-200 capitalize">
                <th className="px-8 py-5">Value Date</th>
                <th className="px-8 py-5">Category Context</th>
                <th className="px-8 py-5">Note / Details</th>
                <th className="px-8 py-5 text-right">Inflow/Outflow</th>
                <th className="px-8 py-5 text-right">Cash in Hand</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 font-mono text-xs">
              {ledgerData.map((row: LedgerDay) => (
                <tr key={row.date} className="hover:bg-slate-50/80 transition-colors group">
                  <td className="px-8 py-5 font-bold text-slate-400 group-hover:text-slate-800 transition-colors">{row.date}</td>
                  <td className="px-8 py-5 font-black text-slate-800 uppercase tracking-tight capitalize">Day Summary</td>
                  <td className="px-8 py-5 italic text-slate-500 capitalize">Accumulated daily activity</td>
                  <td className={`px-8 py-5 text-right font-black text-sm tracking-tight ${(row.income - row.expenses - row.savings) >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                    {(row.income - row.expenses - row.savings) >= 0 ? '+' : ''}RS{formatCurrency(row.income - row.expenses - row.savings)}
                  </td>
                  <td className="px-8 py-5 text-right">
                    <span className="bg-slate-100 text-slate-900 px-4 py-1.5 rounded-full font-black tabular-nums border border-slate-200">
                      RS{formatCurrency(row.available)}
                    </span>
                  </td>
                </tr>
              ))}
              {ledgerData.length === 0 && (
                <tr><td colSpan={5} className="py-24 text-center"><div className="flex flex-col items-center gap-4 opacity-10"><TrendingDown className="w-16 h-16" /><p className="text-sm font-black uppercase tracking-[0.2em] capitalize">Zero Transactions Found For Criteria</p></div></td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ReportView;

import React, { useState, useRef, useEffect } from 'react';
import { TransactionType, Category, Transaction, CategoryConfig } from '../types';
import { DEFAULT_CATEGORIES, ICON_MAP } from '../constants';
import { MoreHorizontal, X, Plus, Building2, Landmark, CreditCard, Wallet, Coins, Globe, PiggyBank, Calendar, Loader2, CheckCircle2 } from 'lucide-react';

interface TransactionFormProps {
  onAdd: (transaction: Transaction) => void;
  onCancel?: () => void;
  editingTransaction?: Transaction | null;
  filterType?: TransactionType;
  customCategories: CategoryConfig[];
  preselectedCategory?: string | null;
  accounts: string[];
  onAddAccount: (name: string) => void;
}

const BANK_ICONS = [Building2, Landmark, CreditCard, Coins, Globe, Wallet, PiggyBank];

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onAdd, 
  onCancel, 
  editingTransaction, 
  filterType, 
  customCategories,
  preselectedCategory,
  accounts,
  onAddAccount
}) => {
  const allCategories = [...DEFAULT_CATEGORIES, ...customCategories];

  const toTitleCase = (str: string) => str.toLowerCase().split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

  const getDefaultCategory = (type?: TransactionType) => {
    if (type === TransactionType.INCOME) return 'Daily Income';
    if (type === TransactionType.SAVINGS) return 'Savings';
    return 'Food'; 
  };

  const [amount, setAmount] = useState<string>('');
  const [category, setCategory] = useState<Category>(getDefaultCategory(filterType));
  const [note, setNote] = useState<string>('');
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [account, setAccount] = useState<string>(accounts[0]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  const amountRef = useRef<HTMLInputElement>(null);

  const getAccountIcon = (name: string, index: number) => {
    const lowerName = name.toLowerCase();
    if (lowerName.includes('amana')) return Landmark;
    if (lowerName.includes('commercial')) return Building2;
    if (lowerName.includes('card')) return CreditCard;
    if (lowerName.includes('cash') || lowerName.includes('wallet')) return Wallet;
    if (lowerName.includes('invest')) return Coins;
    return BANK_ICONS[index % BANK_ICONS.length];
  };

  useEffect(() => {
    if (editingTransaction) {
      setAmount(editingTransaction.amount.toString());
      setCategory(editingTransaction.category);
      setNote(editingTransaction.note === editingTransaction.category ? '' : editingTransaction.note);
      setDate(editingTransaction.date);
      if (editingTransaction.account) setAccount(editingTransaction.account);
    } else if (preselectedCategory) {
      setCategory(preselectedCategory);
      setAmount('');
      setTimeout(() => amountRef.current?.focus(), 100);
    } else {
      setAmount('');
      setNote('');
      setCategory(getDefaultCategory(filterType));
      setDate(new Date().toISOString().split('T')[0]);
      setAccount(accounts[0]);
    }
  }, [editingTransaction, filterType, preselectedCategory, accounts]);

  const setQuickDate = (daysAgo: number) => {
    const d = new Date();
    d.setDate(d.getDate() - daysAgo);
    setDate(d.toISOString().split('T')[0]);
  };

  const handleCategorySelect = (selectedCat: Category) => {
    setCategory(selectedCat);
    amountRef.current?.focus();
  };

  const handleAddAccount = () => {
    const name = window.prompt("Enter New Bank Or Account Name:");
    if (name && name.trim()) {
      const titleCased = toTitleCase(name.trim());
      onAddAccount(titleCased);
      setAccount(titleCased);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || parseFloat(amount) <= 0 || isSubmitting) return;

    setIsSubmitting(true);
    // Visual feedback delay
    await new Promise(r => setTimeout(r, 600));

    const config = allCategories.find(c => c.name === category) || allCategories[allCategories.length - 1];
    const enforcedType = filterType || config.type;

    const transactionData: Transaction = {
      id: editingTransaction ? editingTransaction.id : crypto.randomUUID(),
      date,
      type: enforcedType,
      category,
      amount: parseFloat(amount),
      note: toTitleCase(note || category),
      account: enforcedType === TransactionType.SAVINGS ? account : undefined
    };

    onAdd(transactionData);

    setIsSubmitting(false);
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 2000);

    setAmount('');
    setNote('');
    if (!editingTransaction) {
      amountRef.current?.focus();
    }
  };

  const categoriesToShow = allCategories.filter(cat => {
    const typeToMatch = editingTransaction ? editingTransaction.type : filterType;
    if (!typeToMatch) return true;
    return cat.type === typeToMatch;
  });

  const isEditing = !!editingTransaction;
  const showAccountSelector = (filterType === TransactionType.SAVINGS) || (editingTransaction?.type === TransactionType.SAVINGS);

  return (
    <form id="transaction-form" onSubmit={handleSubmit} className={`bg-white p-5 md:p-8 rounded-2xl md:rounded-[2.5rem] shadow-sm border ${isEditing ? 'border-emerald-500 ring-4 ring-emerald-50' : 'border-slate-100'} space-y-6 transition-all relative overflow-hidden`}>
      {showSuccess && (
        <div className="absolute inset-0 bg-emerald-600/95 backdrop-blur-sm z-[110] flex flex-col items-center justify-center text-white animate-in fade-in duration-300">
           <CheckCircle2 className="w-16 h-16 mb-4 animate-in zoom-in duration-500" />
           <p className="font-black text-xl uppercase tracking-widest">Entry Verified</p>
        </div>
      )}

      <div className="flex items-center justify-between">
        <h3 className="text-lg font-black text-slate-800 capitalize">
          {isEditing ? 'Edit Financial Entry' : (filterType === TransactionType.INCOME ? 'Record New Income' : filterType === TransactionType.SAVINGS ? 'Wealth Contribution' : 'Log New Expense')}
        </h3>
        {isEditing && (
          <button type="button" onClick={onCancel} className="p-2 hover:bg-slate-100 rounded-xl text-slate-400 transition-colors active:scale-90">
            <X className="w-5 h-5" />
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest capitalize">Value Date</label>
          <div className="flex flex-wrap gap-2 mb-2">
            <button 
              type="button" 
              onClick={() => setQuickDate(0)} 
              className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${date === new Date().toISOString().split('T')[0] ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
            >
              Today
            </button>
            <button 
              type="button" 
              onClick={() => setQuickDate(1)} 
              className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${date === new Date(Date.now() - 86400000).toISOString().split('T')[0] ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
            >
              Yesterday
            </button>
          </div>
          <div className="relative">
            <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full pl-11 pr-4 py-3.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-black text-sm bg-slate-50/30 text-slate-900" />
          </div>
        </div>

        <div className="space-y-2">
          <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest capitalize">Transaction Value</label>
          <div className="relative">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-sm font-black text-slate-400">RS</span>
            <input 
              ref={amountRef} 
              type="number" 
              placeholder="0.00" 
              inputMode="decimal" 
              value={amount} 
              onChange={(e) => setAmount(e.target.value)} 
              className="w-full pl-11 pr-4 py-3.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-black text-xl md:text-2xl bg-slate-50/30 tracking-tight tabular-nums text-slate-900" 
              required 
            />
          </div>
        </div>
      </div>

      {showAccountSelector && (
        <div className="space-y-3 animate-in fade-in slide-in-from-top-1">
          <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest capitalize">Settlement Account</label>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {accounts.map((acc, idx) => {
              const isActive = account === acc;
              const IconComp = getAccountIcon(acc, idx);
              return (
                <button
                  key={acc}
                  type="button"
                  onClick={() => setAccount(acc)}
                  className={`flex items-center gap-2 p-3 rounded-xl border-2 transition-all active:scale-95 ${isActive ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-100' : 'bg-white border-slate-100 text-slate-600 hover:border-slate-300'}`}
                >
                  <IconComp className="w-4 h-4 shrink-0" />
                  <span className="text-[10px] font-black truncate capitalize">{acc}</span>
                </button>
              );
            })}
            <button 
              type="button" 
              onClick={handleAddAccount}
              className="flex items-center justify-center gap-2 p-3 rounded-xl border-2 border-dashed border-slate-200 text-slate-400 hover:border-emerald-500 hover:text-emerald-600 transition-all"
            >
              <Plus className="w-4 h-4" />
              <span className="text-[10px] font-black capitalize">New Account</span>
            </button>
          </div>
        </div>
      )}

      {!filterType && !isEditing && (
        <div className="space-y-2">
          <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest capitalize">Select Classification</label>
          <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-2 max-h-48 overflow-y-auto scrollbar-hide p-1 border border-slate-100 rounded-2xl">
            {categoriesToShow.map((cat) => {
              const IconComp = ICON_MAP[cat.iconName] || MoreHorizontal;
              const isActive = category === cat.name;
              return (
                <button key={cat.id} type="button" onClick={() => handleCategorySelect(cat.name)} className={`flex flex-col items-center justify-center p-3 rounded-xl border transition-all active:scale-95 ${isActive ? 'border-emerald-500 bg-emerald-50 text-emerald-700 shadow-sm' : 'border-slate-50 bg-white text-slate-400 hover:border-slate-200'}`}>
                  <div style={{ backgroundColor: cat.color }} className="p-2 rounded-lg text-white mb-1.5 shadow-md"><IconComp className="w-4 h-4" /></div>
                  <span className="text-[9px] text-center font-black capitalize leading-tight">{cat.name}</span>
                </button>
              );
            })}
          </div>
        </div>
      )}

      <div className="space-y-2">
        <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest capitalize">Memorandum / Details</label>
        <input type="text" placeholder="Reference note..." value={note} onChange={(e) => setNote(e.target.value)} className="w-full px-4 py-3.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-bold text-sm bg-slate-50/30 capitalize text-slate-900" />
      </div>

      <div className="flex flex-col sm:flex-row gap-3 pt-3">
        <button 
          type="submit" 
          disabled={isSubmitting}
          className={`flex-grow h-16 ${isEditing ? 'bg-emerald-600' : (filterType === TransactionType.INCOME ? 'bg-emerald-600' : filterType === TransactionType.SAVINGS ? 'bg-indigo-600' : 'bg-slate-900')} text-white font-black rounded-2xl shadow-xl transition-all active:scale-[0.98] capitalize text-base tracking-wide flex items-center justify-center disabled:opacity-50`}
        >
          {isSubmitting ? <Loader2 className="w-6 h-6 animate-spin mr-2" /> : null}
          {isSubmitting ? 'Verifying...' : (isEditing ? 'Update Financial Record' : `Process ${filterType === TransactionType.INCOME ? 'Income' : filterType === TransactionType.SAVINGS ? 'Contribution' : 'Expenditure'}`)}
        </button>
        {isEditing && (
          <button type="button" onClick={onCancel} className="px-8 h-16 bg-slate-100 text-slate-500 font-black rounded-2xl hover:bg-slate-200 transition-all active:scale-95 capitalize text-base">Discard</button>
        )}
      </div>
    </form>
  );
};

