  const quickExpenseCategories = ['Fuel', 'Bike', 'Bike Repair', 'Food', 'Tea', 'Mobile Topup', 'Internet Topup', 'Parcel', 'Buy Accessories', 'Others'];
  const quickIncomeCategories = ['Daily Income', 'Opening Balance'];

  const navItems = [
    { id: 'overview', label: 'Overview', icon: LayoutDashboard },
