          <div className="bg-rose-50 p-6 rounded-[2rem] border border-rose-100 transition-all hover:shadow-lg hover:shadow-rose-100/50"><p className="text-[10px] font-black text-rose-600 tracking-widest mb-1.5 capitalize">Period Outflow</p><p className="text-xl font-black text-rose-700 tracking-tighter">RS{formatCurrency(fullPeriodSummary.expense + fullPeriodSummary.savings)}</p></div>
