import { GoogleGenAI } from "@google/genai";
import { Transaction } from "../types";

// Simple In-Memory Cache And Throttle
let lastCallTime = 0;
const THROTTLE_MS = 30000; // Reduced throttle for Flash model

export const getFinancialInsights = async (transactions: Transaction[]): Promise<string> => {
  if (transactions.length === 0) return "Add Some Transactions To Get Ai-Powered Financial Insights!";

  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    return "Ai Insights Require An Api Key. Please Configure The Api_Key Environment Variable.";
  }

  const now = Date.now();
  if (now - lastCallTime < THROTTLE_MS) {
    return "Analyzing your trends... Please wait a few seconds for the next update.";
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Specifically filter for current month transactions
    const currentMonth = new Date().toISOString().substring(0, 7);
    const monthTransactions = transactions.filter(t => t.date.startsWith(currentMonth));

    if (monthTransactions.length === 0) {
      return `I don't see any activity for the current month (${new Date().toLocaleString('default', { month: 'long', year: 'numeric' })}) yet. Once you start logging, I can provide specific insights for your current cycle!`;
    }

    const sortedTxs = [...monthTransactions].sort((a, b) => b.date.localeCompare(a.date));
    const recentSummary = sortedTxs.map(t => 
      `${t.date}: ${t.type} - ${t.category}: Rs ${t.amount} (${t.note})`
    ).join('\n');

    // Updated prompt to focus specifically on the current month's data and savings growth ratio
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a professional financial advisor. Analyze the following financial activity specifically for the current month (${currentMonth}).

      TASK:
      1. Review the transactions for the current month provided below.
      2. Identify spending trends and patterns unique to this month.
      3. Analyze the savings growth specifically relative to this month's total income and total expenses.
      4. Provide 4 concise, actionable insights focused on:
         - Category spending spikes seen this month (e.g., fuel, food, house expenses).
         - The current month's savings growth vs. expense ratio.
         - A "power move" to optimize liquidity for the rest of this month.

      Current Month Transactions:
      ${recentSummary}`,
      config: {
        temperature: 0.7,
      }
    });

    lastCallTime = Date.now();
    return response.text || "I'm currently observing your spending. Add more data for a deeper analysis!";
  } catch (error: any) {
    console.error("Gemini Error:", error);

    const errorStr = JSON.stringify(error).toLowerCase();
    if (errorStr.includes('429') || errorStr.includes('resource_exhausted')) {
      return "The AI engine is temporarily busy. Your data is safe and local charts are fully active. I'll provide new insights in a moment!";
    }

    return "Financial AI is synchronizing. Please check back in a few minutes.";
  }
};

