import React, { useMemo, useState, useEffect } from 'react';
import { 
  FileSpreadsheet, 
  Table, 
  CalendarDays, 
  TrendingDown, 
  FileText, 
  Filter, 
  ArrowRightLeft, 
  PiggyBank, 
  Landmark,
  PieChart as PieChartIcon,
  Zap,
  ArrowUpCircle,
  ChevronDown,
  Calendar,
  Loader2,
  Download,
  FileJson
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell
} from 'recharts';
import { Transaction, DailySummary, TransactionType, CategoryConfig } from '../types';
import { getCategoryConfig } from '../constants';
import DateDropdown, { DatePreset } from './DateDropdown';

interface LedgerDay {
  date: string;
  income: number;
  expenses: number;
  savings: number;
  available: number;
  categories: Record<string, number>;
}

interface ReportViewProps {
  transactions: Transaction[];
  summary: DailySummary;
  customCategories: CategoryConfig[];
  budgets: Record<string, number>;
}

const ReportView: React.FC<ReportViewProps> = ({ transactions, summary, customCategories }) => {
  const todayStr = new Date().toISOString().split('T')[0];

  const [datePreset, setDatePreset] = useState<DatePreset>('thisMonth');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>(todayStr);
  const [typeFilter, setTypeFilter] = useState<'ALL' | TransactionType>('ALL');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isExcelGenerating, setIsExcelGenerating] = useState(false);

  useEffect(() => {
    const now = new Date();
    let start = '';
    let end = todayStr;

    switch (datePreset) {
      case 'today':
        start = todayStr;
        end = todayStr;
        break;
      case 'yesterday':
        const yesterday = new Date(now);
        yesterday.setDate(now.getDate() - 1);
        start = yesterday.toISOString().split('T')[0];
        end = start;
        break;
      case 'last7':
        const last7 = new Date(now);
        last7.setDate(now.getDate() - 7);
        start = last7.toISOString().split('T')[0];
        end = todayStr;
        break;
      case 'thisMonth':
        start = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
        end = todayStr;
        break;
      case 'lastMonth':
        const firstOfLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
        const lastOfLastMonth = new Date(now.getFullYear(), now.getMonth(), 0);
        start = firstOfLastMonth.toISOString().split('T')[0];
        end = lastOfLastMonth.toISOString().split('T')[0];
        break;
      case 'all':
        start = '';
        end = todayStr;
        break;
      case 'custom':
        if (!startDate) {
          setStartDate(new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0]);
        }
        return;
    }

    setStartDate(start);
    setEndDate(end);
  }, [datePreset, todayStr]);

  const escapeXML = (str: any) => {
    if (str === null || str === undefined) return '';
    return str.toString()
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&apos;');
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat(undefined, { 
    minimumFractionDigits: 2, 
    maximumFractionDigits: 2 
  }).format(val);

  const periodTransactions = useMemo(() => {
    return transactions.filter(t => {
      let matchesDate = true;
      if (startDate) matchesDate = t.date >= startDate;
      if (matchesDate && endDate) matchesDate = matchesDate && t.date <= endDate;

      if (!matchesDate) return false;
      if (typeFilter !== 'ALL' && t.type !== typeFilter) return false;

      return true;
    }).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, startDate, endDate, typeFilter]);

  const ledgerData = useMemo(() => {
    const allDates: string[] = Array.from(new Set(transactions.map(t => t.date))).sort() as string[];
    const ledgerMap: Record<string, LedgerDay> = {};
    let runningBalance = 0;

    allDates.forEach((date: string) => {
      const dayTxs = transactions.filter(t => t.date === date);
      const dayIncome = dayTxs.filter(t => t.type === TransactionType.INCOME).reduce((sum, t) => sum + t.amount, 0);
      const dayExpenses = dayTxs.filter(t => t.type === TransactionType.EXPENSE).reduce((sum, t) => sum + t.amount, 0);
      const daySavings = dayTxs.filter(t => t.type === TransactionType.SAVINGS).reduce((sum, t) => sum + t.amount, 0);

      const catBreakdown: Record<string, number> = {};
      dayTxs.forEach((t: Transaction) => {
        catBreakdown[t.category] = (catBreakdown[t.category] || 0) + t.amount;
      });

      runningBalance += dayIncome - dayExpenses - daySavings;

      ledgerMap[date] = { 
        date, 
        income: dayIncome, 
        expenses: dayExpenses,
        savings: daySavings,
        available: runningBalance,
        categories: catBreakdown
      };
    });

    return Object.keys(ledgerMap)
      .filter(date => {
        let matches = true;
        if (startDate) matches = date >= startDate;
        if (matches && endDate) matches = matches && date <= endDate;
        return matches;
      })
      .sort((a, b) => b.localeCompare(a))
      .map(date => ledgerMap[date])
      .filter((d): d is LedgerDay => d !== undefined);
  }, [transactions, startDate, endDate]);

  const fullPeriodSummary = useMemo(() => {
    let income = 0, expense = 0, savings = 0;
    periodTransactions.forEach(t => {
      if (t.type === TransactionType.INCOME && t.category !== 'Opening Balance') income += t.amount;
      else if (t.type === TransactionType.EXPENSE) expense += t.amount;
      else if (t.type === TransactionType.SAVINGS) savings += t.amount;
    });
    return { income, expense, savings, net: income - expense - savings };
  }, [periodTransactions]);

  const categoryConcentrationData = useMemo(() => {
    const dataMap: Record<string, { amount: number, color: string }> = {};
    periodTransactions
      .forEach(t => {
        if (!dataMap[t.category]) {
          const config = getCategoryConfig(t.category, customCategories);
          dataMap[t.category] = { amount: 0, color: config.color };
        }
        dataMap[t.category].amount += t.amount;
      });
    return Object.entries(dataMap)
      .map(([name, data]: [string, { amount: number, color: string }]) => ({
        name,
        amount: data.amount,
        color: data.color
      }))
      .sort((a, b) => b.amount - a.amount);
  }, [periodTransactions, customCategories]);

  const downloadCSV = (content: string, filename: string) => {
    const blob = new Blob([content], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const generateConcentrationCSV = () => {
    const headers = ['Category', 'Amount (RS)'];
    const rows = categoryConcentrationData.map(item => [
      `"${item.name.replace(/"/g, '""')}"`,
      item.amount.toFixed(2)
    ]);
    const csvContent = [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
    downloadCSV(csvContent, `SpendWise_Concentration_${startDate || 'all'}_to_${endDate}.csv`);
  };

  const generateMainReportCSV = async () => {
    setIsGenerating(true);
    await new Promise(r => setTimeout(r, 600));

    const columns = [
      'Date', 
      'Opening Balance', 
      'Daily Income', 
      'Fuel', 
      'Bike', 
      'Bike Repair', 
      'Food', 
      'Tea', 
      'House Expenses',
      'Mobile Topup', 
      'Internet Topup', 
      'Parcel', 
      'Buy Accessories', 
      'Savings', 
      'Others',
      'Available Balance'
    ];

    const chronologicalLedger = [...ledgerData].sort((a, b) => a.date.localeCompare(b.date));
    const csvRows: string[] = [columns.join(',')];

    const totals: Record<string, number> = {};
    columns.forEach(col => totals[col] = 0);

    chronologicalLedger.forEach((day: LedgerDay) => {
      const row = columns.map(col => {
        if (col === 'Date') return day.date;
        if (col === 'Available Balance') return day.available.toFixed(2);

        let val = 0;
        if (col === 'Opening Balance') val = day.categories['Opening Balance'] || 0;
        else if (col === 'Daily Income') val = day.categories['Daily Income'] || 0;
        else val = day.categories[col] || 0;

        totals[col] += val;
        return val.toFixed(2);
      });
      csvRows.push(row.join(','));
    });

    const totalsRow = columns.map(col => {
      if (col === 'Date') return 'GRAND TOTAL';
      if (col === 'Available Balance') {
        const lastDay = chronologicalLedger[chronologicalLedger.length - 1];
        return lastDay ? lastDay.available.toFixed(2) : '0.00';
      }
      return totals[col].toFixed(2);
    });
    csvRows.push(totalsRow.join(','));

    downloadCSV(csvRows.join('\n'), `SpendWise_Full_Report_${startDate || 'all'}_to_${endDate}.csv`);
    setIsGenerating(false);
  };

  const generateExcelXML = async () => {
    setIsExcelGenerating(true);
