      <Cell ss:StyleID="Currency"><Data ss:Type="Number">${finalAvail}</Data></Cell>
    </Row>`;

    xml += `
  </Table>
 </Worksheet>
</Workbook>`;

    const blob = new Blob([xml], { type: 'application/vnd.ms-excel' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
